import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  TouchableOpacity,
  Modal,
  ScrollView,
  Platform,
  TextInput,
} from 'react-native';
import DateTimePicker from '@react-native-community/datetimepicker';
import colors from '../globals/colors';
import { FontSizes } from '../globals/constants';
import { useTranslation } from 'react-i18next';
import { Ionicons as Icon } from '@expo/vector-icons';
import { I18nManager } from 'react-native';

interface DatePickerProps {
  value: Date | null;
  onChange: (date: Date | null) => void;
  placeholder?: string;
  label?: string;
  minimumDate?: Date;
  maximumDate?: Date;
  disabled?: boolean;
}

// Helper function to format date to Hebrew locale
const formatDate = (date: Date | null): string => {
  if (!date || !(date instanceof Date) || isNaN(date.getTime())) {
    return '';
  }
  return date.toLocaleDateString('he-IL', {
    day: '2-digit',
    month: '2-digit',
    year: 'numeric',
  });
};

// Helper function to validate and create Date
const ensureValidDate = (date: Date | null | undefined): Date => {
  if (!date) return new Date();
  if (date instanceof Date && !isNaN(date.getTime())) {
    return date;
  }
  return new Date();
};

export default function DatePicker({
  value,
  onChange,
  placeholder,
  label,
  minimumDate,
  maximumDate,
  disabled = false,
}: DatePickerProps) {
  const { t } = useTranslation(['common', 'trump']);
  const [isVisible, setIsVisible] = useState(false);
  const [selectedDate, setSelectedDate] = useState<Date>(() => ensureValidDate(value));
  const [showNativePicker, setShowNativePicker] = useState(false);

  // Update selected date when value prop changes
  useEffect(() => {
    const validDate = ensureValidDate(value);
    setSelectedDate(validDate);
  }, [value]);

  const handleOpen = () => {
    if (disabled) return;
    const validDate = ensureValidDate(value);
    setSelectedDate(validDate);

    if (Platform.OS === 'web') {
      setIsVisible(true);
    } else {
      // On mobile, show native picker
      setShowNativePicker(true);
    }
  };

  const handleConfirm = () => {
    onChange(selectedDate);
    setIsVisible(false);
  };

  const handleCancel = () => {
    setIsVisible(false);
    setShowNativePicker(false);
  };

  const handleNativeDateChange = (event: any, date?: Date) => {
    setShowNativePicker(false);
    if (Platform.OS === 'android') {
      // Android closes automatically
    }
    if (date) {
      onChange(date);
    }
  };

  // Generate date options for custom picker (web)
  const currentYear = new Date().getFullYear();
  const years = Array.from({ length: 5 }, (_, i) => currentYear + i);
  const months = [
    'ינואר', 'פברואר', 'מרץ', 'אפריל', 'מאי', 'יוני',
    'יולי', 'אוגוסט', 'ספטמבר', 'אוקטובר', 'נובמבר', 'דצמבר'
  ];
  const daysInMonth = (year: number, month: number) => {
    return new Date(year, month + 1, 0).getDate();
  };

  const selectedYear = selectedDate.getFullYear();
  const selectedMonth = selectedDate.getMonth();
  const selectedDay = selectedDate.getDate();
  const days = Array.from(
    { length: daysInMonth(selectedYear, selectedMonth) },
    (_, i) => i + 1
  );

  const handleYearChange = (year: number) => {
    const newDate = new Date(selectedDate);
    newDate.setFullYear(year);
    // Adjust day if needed (e.g., Feb 29 -> Feb 28)
    const maxDay = daysInMonth(year, newDate.getMonth());
    if (newDate.getDate() > maxDay) {
      newDate.setDate(maxDay);
    }
    setSelectedDate(newDate);
  };

  const handleMonthChange = (month: number) => {
    const newDate = new Date(selectedDate);
    newDate.setMonth(month);
    // Adjust day if needed
    const maxDay = daysInMonth(newDate.getFullYear(), month);
    if (newDate.getDate() > maxDay) {
      newDate.setDate(maxDay);
    }
    setSelectedDate(newDate);
  };

  const handleDayChange = (day: number) => {
    const newDate = new Date(selectedDate);
    newDate.setDate(day);
    setSelectedDate(newDate);
  };

  const displayValue = formatDate(value ? ensureValidDate(value) : null);

  return (
    <View style={styles.container}>
      {label && <Text style={styles.label}>{label}</Text>}

      {Platform.OS === 'web' ? (
        <>
          <TouchableOpacity
            style={[styles.dateButton, disabled && styles.disabled]}
            onPress={handleOpen}
            disabled={disabled}
          >
            <Text style={[styles.dateText, !displayValue && styles.placeholderText]}>
              {displayValue || placeholder || t('trump:ui.selectDate') || 'בחר תאריך'}
            </Text>
            <Icon name="calendar-outline" size={20} color={colors.textSecondary} />
          </TouchableOpacity>

          <Modal
            visible={isVisible}
            transparent={true}
            animationType="slide"
            onRequestClose={handleCancel}
          >
            <View style={styles.modalOverlay}>
              <View style={styles.modalContent}>
                <View style={styles.modalHeader}>
                  <Text style={styles.modalTitle}>
                    {placeholder || t('trump:ui.selectDate') || 'בחר תאריך'}
                  </Text>
                  <TouchableOpacity onPress={handleCancel} style={styles.closeButton}>
                    <Icon name="close" size={24} color={colors.textPrimary} />
                  </TouchableOpacity>
                </View>

                <View style={styles.pickerContainer}>
                  {/* Year Picker */}
                  <View style={styles.pickerColumn}>
                    <Text style={styles.pickerLabel}>{t('common:date.year') || 'שנה'}</Text>
                    <ScrollView
                      style={styles.pickerScroll}
                      showsVerticalScrollIndicator={false}
                      snapToInterval={40}
                    >
                      {years.map((year) => (
                        <TouchableOpacity
                          key={year}
                          style={[
                            styles.pickerItem,
                            selectedYear === year && styles.selectedItem,
                          ]}
                          onPress={() => handleYearChange(year)}
                        >
                          <Text
                            style={[
                              styles.pickerItemText,
                              selectedYear === year && styles.selectedItemText,
                            ]}
                          >
                            {year}
                          </Text>
                        </TouchableOpacity>
                      ))}
                    </ScrollView>
                  </View>

                  {/* Month Picker */}
                  <View style={styles.pickerColumn}>
                    <Text style={styles.pickerLabel}>{t('common:date.month') || 'חודש'}</Text>
                    <ScrollView
                      style={styles.pickerScroll}
                      showsVerticalScrollIndicator={false}
                      snapToInterval={40}
                    >
                      {months.map((month, index) => (
                        <TouchableOpacity
                          key={index}
                          style={[
                            styles.pickerItem,
                            selectedMonth === index && styles.selectedItem,
                          ]}
                          onPress={() => handleMonthChange(index)}
                        >
                          <Text
                            style={[
                              styles.pickerItemText,
                              selectedMonth === index && styles.selectedItemText,
                            ]}
                          >
                            {month}
                          </Text>
                        </TouchableOpacity>
                      ))}
                    </ScrollView>
                  </View>

                  {/* Day Picker */}
                  <View style={styles.pickerColumn}>
                    <Text style={styles.pickerLabel}>{t('common:date.day') || 'יום'}</Text>
                    <ScrollView
                      style={styles.pickerScroll}
                      showsVerticalScrollIndicator={false}
                      snapToInterval={40}
                    >
                      {days.map((day) => (
                        <TouchableOpacity
                          key={day}
                          style={[
                            styles.pickerItem,
                            selectedDay === day && styles.selectedItem,
                          ]}
                          onPress={() => handleDayChange(day)}
                        >
                          <Text
                            style={[
                              styles.pickerItemText,
                              selectedDay === day && styles.selectedItemText,
                            ]}
                          >
                            {day}
                          </Text>
                        </TouchableOpacity>
                      ))}
                    </ScrollView>
                  </View>
                </View>

                <View style={styles.modalFooter}>
                  <TouchableOpacity style={styles.cancelButton} onPress={handleCancel}>
                    <Text style={styles.cancelButtonText}>{t('common:cancel')}</Text>
                  </TouchableOpacity>
                  <TouchableOpacity style={styles.confirmButton} onPress={handleConfirm}>
                    <Text style={styles.confirmButtonText}>{t('common:confirm')}</Text>
                  </TouchableOpacity>
                </View>
              </View>
            </View>
          </Modal>
        </>
      ) : (
        <>
          <TouchableOpacity
            style={[styles.dateButton, disabled && styles.disabled]}
            onPress={handleOpen}
            disabled={disabled}
          >
            <Text style={[styles.dateText, !displayValue && styles.placeholderText]}>
              {displayValue || placeholder || t('trump:ui.selectDate') || 'בחר תאריך'}
            </Text>
            <Icon name="calendar-outline" size={20} color={colors.textSecondary} />
          </TouchableOpacity>

          {showNativePicker && (
            <DateTimePicker
              value={selectedDate}
              mode="date"
              display="default"
              onChange={handleNativeDateChange}
              minimumDate={minimumDate}
              maximumDate={maximumDate}
            />
          )}
        </>
      )}
    </View>
  );
}

