// --- AnimatedStatsBubble Component ---

interface AnimatedStatsBubbleProps {
  id: string;
  size: number;
  x: number;
  y: number;
  value: number;
  name: string;
  icon: string;
  category: string;
  color: string;
  directionX: number;
  directionY: number;
  delay: number;
  isSelected: boolean;
  onPress: (id: string) => void;
  isBackground?: boolean;
}

/**
 * קומפוננטת בועה בודדת עם אנימציות עדינות
 */
const AnimatedStatsBubble: React.FC<AnimatedStatsBubbleProps> = ({
  id,
  size,
  x,
  y,
  value,
  name,
  icon,
  category,
  color,
  directionX,
  directionY,
  delay,
  isSelected,
  onPress,
  isBackground = false,
}) => {
  const floatOffset = useSharedValue(0);
  const pulseScale = useSharedValue(1);
  const animatedOpacity = useSharedValue(0.85);
  const animatedScale = useSharedValue(1);

  useEffect(() => {
    floatOffset.value = withRepeat(
      withDelay(
        delay,
        withTiming(1, {
          duration: 4000 + Math.random() * 2000,
          easing: Easing.inOut(Easing.sin),
        })
      ),
      -1,
      true
    );
  }, [delay, floatOffset]);

  useEffect(() => {
    pulseScale.value = withRepeat(
      withDelay(
        delay + 500,
        withTiming(1.08, {
          duration: 2500 + Math.random() * 1500,
          easing: Easing.inOut(Easing.quad),
        })
      ),
      -1,
      true
    );
  }, [delay, pulseScale]);

  useEffect(() => {
    animatedOpacity.value = withTiming(isSelected ? 1 : 0.85, {
      duration: 300,
    });
    animatedScale.value = withSpring(isSelected ? 1.15 : 1, {
      damping: 12,
      stiffness: 150,
    });
  }, [isSelected, animatedOpacity, animatedScale]);

  const handleInternalPress = useCallback(
    (event: GestureResponderEvent) => {
      if (!isBackground) {
        onPress(id);
      }
    },
    [id, onPress, isBackground]
  );

  const animatedStyle = useAnimatedStyle(() => {
    const floatX = interpolate(
      floatOffset.value,
      [0, 1],
      [0, 6 * directionX]
    );
    const floatY = interpolate(
      floatOffset.value,
      [0, 1],
      [0, 8 * directionY]
    );

    let backgroundColor, borderColor, shadowColor;

    if (isBackground) {
      backgroundColor = color + '15';
      borderColor = color + '30';
      shadowColor = color + '20';
    } else {
      backgroundColor = color + '20';
      borderColor = color;
      shadowColor = color + '40';

      if (isSelected) {
        backgroundColor = color + '40';
        borderColor = color;
        shadowColor = color + '60';
      }
    }

    return {
      transform: [
        { translateX: x + floatX },
        { translateY: y + floatY },
        { scale: animatedScale.value * pulseScale.value },
      ] as any,
      backgroundColor,
      borderColor,
      shadowColor,
      opacity: animatedOpacity.value,
    };
  });

  const iconSize = Math.max(size * 0.15, 16);
  const valueSize = Math.max(size * 0.18, 14);
  const nameSize = Math.max(size * 0.08, 10);

  return (
    <TouchableWithoutFeedback onPress={handleInternalPress}>
      <Animated.View
        style={[
          localStyles.bubble,
          {
            width: size,
            height: size,
            borderRadius: size / 2,
            zIndex: isBackground ? 1 : isSelected ? 100 : 10,
          },
          animatedStyle,
        ]}
      >
        {!isBackground && (
          <View style={localStyles.bubbleContent}>
            {/* Icon */}
            <Text style={[localStyles.bubbleIcon, { fontSize: iconSize }]}>
              {icon}
            </Text>

            {/* Value */}
            <Text
              style={[
                localStyles.bubbleValue,
                {
                  fontSize: valueSize,
                  color: isSelected ? colors.textPrimary : colors.textSecondary,
                },
              ]}
              numberOfLines={1}
              adjustsFontSizeToFit
              minimumFontScale={0.6}
            >
              {value.toLocaleString()}
            </Text>

            {/* Name */}
            <Text
              style={[
                localStyles.bubbleName,
                {
                  fontSize: nameSize,
                  color: isSelected ? colors.textPrimary : colors.textTertiary,
                  lineHeight: nameSize * 1.3,
                },
              ]}
              numberOfLines={3}
              adjustsFontSizeToFit
              minimumFontScale={0.4}
            >
              {name}
            </Text>
          </View>
        )}
      </Animated.View>
    </TouchableWithoutFeedback>
  );
};

