          setRecentPosts([]);
        }
      } catch (error) {
        console.error('❌ שגיאה בטעינת פוסטים להיסטוריה:', error);
        setRecentPosts([]);
      }

      // עדיין טוען rides לצורך history (legacy support)
      const shouldIncludePast = includePastOverride !== undefined
        ? includePastOverride
