      const userRecent = (myHistory || []).map((r: any) => ({
        ...r,
        status: r.status || 'active',
        price: r.price || 0,
      }));
      setRecentRides(userRecent);
    } catch (e) {
      console.error("❌ Failed to load rides", e);
      setAllRides([]);
      setRecentRides([]);
    }
  }, [selectedUser?.id, t, selectedFilters]);

  // Reload rides when includePast filter changes
  useEffect(() => {
