// ========================================
// TYPE DEFINITIONS
// ========================================

/**
 * Standard API response format
 * Consistent across all endpoints for predictable error handling
 */
export interface ApiResponse<T = any> {
  /** Whether the request was successful */
  success: boolean;
  /** Response data if successful */
  data?: T;
  /** Error message if unsuccessful */
  error?: string;
  /** Additional error context */
  message?: string;
  /** Response metadata */
  metadata?: {
    requestId?: string;
    timestamp?: string;
    duration?: number;
    cached?: boolean;
  };
}

/**
 * Request options for API calls
 */
export interface RequestOptions {
  /** Whether to cache the response (GET requests only) */
  enableCache?: boolean;
  /** Cache duration in milliseconds */
  cacheDuration?: number;
  /** Request timeout in milliseconds */
  timeout?: number;
  /** Number of retry attempts */
  retries?: number;
  /** Whether to include authentication headers */
  authenticated?: boolean;
  /** Custom headers to include */
  headers?: Record<string, string>;
}

/**
 * Error categories for better error handling
 */
export type ApiErrorType = 
  | 'NETWORK_ERROR'       // Network connectivity issues
  | 'AUTHENTICATION_ERROR' // Authentication/authorization failures  
  | 'VALIDATION_ERROR'    // Input validation failures
  | 'SERVER_ERROR'        // Internal server errors
  | 'RATE_LIMIT_ERROR'    // Rate limiting triggered
  | 'TIMEOUT_ERROR'       // Request timeout
  | 'UNKNOWN_ERROR';      // Unclassified errors

/**
 * Detailed error information
 */
export interface ApiError {
  type: ApiErrorType;
  message: string;
  details?: string;
  statusCode?: number;
  retryable?: boolean;
  retryAfter?: number;
}

