/**
 * Store authentication token securely
 * Convenience method for storing auth tokens with proper security settings
 */
export const storeAuthToken = async (
  tokenType: 'access' | 'refresh',
  token: string
): Promise<StorageResult> => {
  return SecureStorageClass.setItem(`${tokenType}_token`, token, {
    encrypted: true,
    accessLevel: 'whenUnlocked',
    allowFallback: false, // Never allow fallback for tokens
  });
};

/**
 * Retrieve authentication token
 * Convenience method for getting auth tokens
 */
export const getAuthToken = async (
  tokenType: 'access' | 'refresh'
): Promise<StorageResult<string>> => {
  return SecureStorageClass.getItem(`${tokenType}_token`, {
    allowFallback: false,
  });
};

/**
 * Store user profile data
 * Convenience method for storing user profile with caching
 */
export const storeUserProfile = async (
  userId: string,
  profile: any,
  ttl: number = 15 * 60 * 1000 // 15 minutes default
): Promise<StorageResult> => {
  return SecureStorageClass.setItem(`user_profile_${userId}`, profile, {
    encrypted: false, // Profile data is not sensitive
    ttl,
    allowFallback: true,
  });
};

/**
 * Get user profile from cache
 */
export const getUserProfile = async (userId: string): Promise<StorageResult<any>> => {
  return SecureStorageClass.getItem(`user_profile_${userId}`, {
    allowFallback: true,
  });
};

// ========================================
// EXPORTS
// ========================================

export const SecureStorage = SecureStorageClass;
export default SecureStorage;

/**
 * ========================================
 * SECURITY BEST PRACTICES
 * ========================================
 * 
 * 1. TOKEN STORAGE:
 *    - Always use encrypted storage for tokens
 *    - Never allow fallback for authentication tokens
 *    - Set appropriate access levels (whenUnlocked)
 * 
 * 2. DATA CLASSIFICATION:
 *    - Sensitive: tokens, passwords, private keys -> secure storage only
 *    - Personal: profile data, preferences -> secure storage with fallback
 *    - Public: app settings, cache data -> regular storage OK
 * 
 * 3. EXPIRATION:
 *    - Set TTL for cached data
 *    - Regular cleanup of expired items
 *    - Monitor storage usage
 * 
 * 4. ERROR HANDLING:
 *    - Always check storage results
 *    - Handle storage unavailability gracefully
 *    - Log storage errors for monitoring
 * 
 * 5. PLATFORM CONSIDERATIONS:
 *    - iOS: Keychain may require user authentication
 *    - Android: Keystore may not be available on all devices
 *    - Web: sessionStorage is cleared when tab closes
 * 
 * ========================================
 * USAGE EXAMPLES
 * ========================================
 * 
 * // Store authentication token (most secure)
 * await storeAuthToken('access', accessToken);
 * 
 * // Store user profile (cached)
 * await storeUserProfile(userId, profileData);
 * 
 * // Store temporary data with expiration
 * await SecureStorage.setItem('temp_data', data, { 
 *   ttl: 5 * 60 * 1000, // 5 minutes
 *   encrypted: false 
 * });
 * 
 * // Retrieve with error handling
 * const result = await getAuthToken('access');
 * if (result.success) {
 *   console.log('Token:', result.data);
 * } else {
 *   console.error('No token:', result.error);
 * }
 * 
 * // Cleanup expired items
 * const cleaned = await SecureStorage.cleanup();
 * console.log('Cleaned items:', cleaned.data);
 */

import { useCallback, useRef } from 'react';
import { Alert } from 'react-native';
import { useNavigation, useFocusEffect, useRoute } from '@react-navigation/native';
import { useUser } from '../stores/userStore';

export function useAdminProtection(allowViewOnly?: boolean) {
    const { isAdmin, isLoading, selectedUser, refreshUserRoles, isAuthenticated, isGuestMode } = useUser();
    const navigation = useNavigation<any>();
    const route = useRoute();
    const routeParams = (route.params as any) || {};
    const isViewOnly = routeParams?.viewOnly === true;
    const isVerifyingRef = useRef(false);
    const lastCheckRef = useRef<number>(0);

    const handleUnauthorized = useCallback(() => {
        Alert.alert('שגיאה', 'אין לך הרשאות לצפות בדף זה');
        if (navigation.canGoBack()) {
            navigation.goBack();
        } else {
            navigation.navigate('Home');
        }
    }, [navigation]);

    const verifyAdminStatus = useCallback(async () => {
        // Prevent multiple simultaneous checks
        if (!selectedUser?.id || isVerifyingRef.current) return;

        // Throttle checks - don't check more than once every 5 seconds
        const now = Date.now();
        if (now - lastCheckRef.current < 5000) {
            return;
        }

        try {
            isVerifyingRef.current = true;
            lastCheckRef.current = now;

            console.log('🔐 Admin protection: Verifying admin status for user:', selectedUser.email);

            // Refresh user roles from database
            // This will update the store if roles changed
            await refreshUserRoles();

            // The isAdmin flag will be updated automatically by the store
            // If it becomes false, the next render will catch it in the local check below

        } catch (err) {
            console.warn('🔐 Admin verification failed (network error or other)', err);
        } finally {
            isVerifyingRef.current = false;
        }
    }, [selectedUser?.id, selectedUser?.email, refreshUserRoles]);

    useFocusEffect(
        useCallback(() => {
            // If view-only mode is allowed and active, allow everyone (including unauthenticated)
            if (allowViewOnly && isViewOnly) {
                // In view-only mode, allow everyone - no authentication required
                console.log('🔐 View-only protection: Allowing access (view-only mode)');
                return;
            }

            // 1. Immediate local check for admin access
            if (!isLoading && !isAdmin) {
                console.log('🔐 Admin protection: User not admin (local check), redirecting');
                handleUnauthorized();
                return;
            }

            // 2. Server check if locally admin
            // This runs every time the screen comes into focus
            if (!isLoading && isAdmin && selectedUser) {
                verifyAdminStatus();
            }
        }, [isAdmin, isLoading, selectedUser, verifyAdminStatus, handleUnauthorized, allowViewOnly, isViewOnly, isAuthenticated, isGuestMode])
    );

    return { isAuthorized: isAdmin || (allowViewOnly && isViewOnly && (isAuthenticated || isGuestMode)) };
}

import { useState, useCallback, useEffect } from 'react';
import { postsService } from '../utils/postsService';
import databaseService from '../utils/databaseService';
import { logger } from '../utils/loggerService';
import { FeedItem } from '../types/feed';
import { useUser } from '../stores/userStore';

const NUM_ITEMS = 50; // Per page/batch

export const useFeedData = (feedMode: 'friends' | 'discovery') => {
    const { selectedUser: currentUser } = useUser();
    const [feed, setFeed] = useState<FeedItem[]>([]);
    const [loading, setLoading] = useState(true);
    const [refreshing, setRefreshing] = useState(false);

    // Helper to map API post to FeedItem
    const mapPostToItem = (post: any): FeedItem => {
        // For ride posts, extract ride-specific data
        // Helper to format date/time safely
        let rideData: any = {};
        const formatRideTime = (dateIso: string) => {
            if (!dateIso) return { time: '', date: '' };
            const dep = new Date(dateIso);
            if (isNaN(dep.getTime())) return { time: '', date: '' };

            const hours = dep.getHours().toString().padStart(2, '0');
            const minutes = dep.getMinutes().toString().padStart(2, '0');

            const day = dep.getDate().toString().padStart(2, '0');
            const month = (dep.getMonth() + 1).toString().padStart(2, '0');
            const year = dep.getFullYear();

            return {
                time: `${hours}:${minutes}`,
                date: `${day}.${month}.${year}`
            };
        };

        // 1. Try ride_data from DB Join
        if (post.ride_data) {
            const rd = post.ride_data;
            const { time, date } = formatRideTime(rd.departure_time);

            rideData = {
                from: typeof rd.from_location === 'string' ? rd.from_location : (rd.from_location?.name || rd.from_location?.city || ''),
                to: typeof rd.to_location === 'string' ? rd.to_location : (rd.to_location?.name || rd.to_location?.city || ''),
                seats: rd.available_seats || 0,
                price: rd.price_per_seat || 0,
                time,
                date,
                status: rd.status // Add status for ride
            };
        }
        // 2. Fallback to metadata
        else if ((post.post_type === 'ride' || post.post_type === 'ride_offered') && post.metadata) {
            const meta = typeof post.metadata === 'string' ? JSON.parse(post.metadata) : post.metadata;
            const r = meta.ride || meta;

            // Check departure_time (schema) or time/date (legacy/manual)
            let timeStr = r.time || '';
            let dateStr = r.date || '';

            if (r.departure_time) {
                const formatted = formatRideTime(r.departure_time);
                if (formatted.time) timeStr = formatted.time;
                if (formatted.date) dateStr = formatted.date;
            }

            rideData = {
                from: typeof r.from_location === 'string' ? r.from_location : (r.from_location?.name || r.from_location?.city || r.from || ''),
                to: typeof r.to_location === 'string' ? r.to_location : (r.to_location?.name || r.to_location?.city || r.to || ''),
                seats: r.available_seats || r.seats || 0,
                price: r.price_per_seat || r.price || 0,
                time: timeStr,
                date: dateStr
            };
        }

        // Ensure user is always defined
        const author = post.author || {};
        const userId = author.id || post.author_id || 'unknown';
        const userName = author.name || 'common.unknownUser';
        const userAvatar = author.avatar_url || undefined;

        // Get status from item_data or ride_data or default
        let itemStatus: string | undefined;
        if (post.item_data) {
            itemStatus = post.item_data.status;
        } else if (post.ride_data) {
            itemStatus = post.ride_data.status;
        }

        // Parse metadata to get item_id if needed
        let metadataItemId: string | undefined;
        try {
            if (post.metadata) {
                const metadata = typeof post.metadata === 'string' ? JSON.parse(post.metadata) : post.metadata;
                metadataItemId = metadata?.item_id;
            }
        } catch (e) {
            // Ignore parse errors
        }

        // For items: ALWAYS prefer item_data.id (from JOIN with items table) - this is the most reliable source
        // Then try metadata.item_id, then item_id column (if not timestamp)
        // This is a workaround for cases where item_id column was stored incorrectly as timestamp
        let finalItemId: string | undefined;
        if (post.item_data?.id) {
            // item_data.id comes from JOIN with items table - this is the most reliable
            finalItemId = post.item_data.id;
        } else if (metadataItemId && !/^\d{10,13}$/.test(metadataItemId)) {
            // metadata.item_id is valid (not timestamp) - this is stored when post is created
            finalItemId = metadataItemId;
        } else if (post.item_id && !/^\d{10,13}$/.test(post.item_id)) {
            // item_id column is valid (not timestamp)
            finalItemId = post.item_id;
        } else {
            // If all else fails and we have a timestamp, we can't use it
            // But we'll log it for debugging
            finalItemId = undefined;
        }

        // Debug log for item/donation posts to help diagnose issues
        if ((post.post_type === 'item' || post.post_type === 'donation')) {
            if (!finalItemId || /^\d{10,13}$/.test(finalItemId || '')) {
                console.warn('⚠️ Invalid item ID for post:', {
                    postId: post.id,
                    postType: post.post_type,
                    finalItemId,
                    item_id_column: post.item_id,
                    item_data_id: post.item_data?.id,
                    metadata_item_id: metadataItemId,
                    hasItemData: !!post.item_data
                });
            }
        }

        return {
            id: post.id,
            type: post.post_type || 'post',
            subtype: post.post_type, // e.g. 'task_assignment', 'ride'
            title: post.title || 'post.noTitle', // Use key or default in UI
            description: post.description || '',
            thumbnail: post.images && post.images.length > 0 ? post.images[0] : null,
            user: {
                id: userId,
                name: userName,
                avatar: userAvatar,
            },
            likes: parseInt(post.likes || '0'),
            comments: parseInt(post.comments || '0'),
            isLiked: post.is_liked || false,
            timestamp: (post.created_at && !isNaN(new Date(post.created_at).getTime()))
                ? new Date(post.created_at).toISOString()
                : new Date().toISOString(),
            taskData: post.task ? {
                id: post.task.id,
                title: post.task.title,
                status: post.task.status
            } : undefined,
            // Add status for items and donations
            status: itemStatus,
            // Add IDs for updating posts
            itemId: finalItemId,
            rideId: post.ride_id || post.ride_data?.id,
            taskId: post.task_id || post.task?.id,
            // Add ride-specific fields if this is a ride post
            ...rideData
        };
    };

    const loadFeed = useCallback(async (isRefresh = false) => {
        if (isRefresh) {
            setRefreshing(true);
        } else {
            setLoading(true);
        }

        try {
            logger.debug('useFeedData', 'Loading feed', { feedMode, userId: currentUser?.id });

            // 1. Fetch Posts from Backend
            const postsResponse = await postsService.getPosts(NUM_ITEMS, 0, feedMode === 'friends' ? currentUser?.id : undefined);
            const rawPosts = postsResponse.success ? (postsResponse.data || []) : [];
            const mappedPosts = rawPosts.map(mapPostToItem);

            const allContent: FeedItem[] = [...mappedPosts];
            const existingIds = new Set(allContent.map(item => item.id));

            // Track IDs of tasks that already have a post to avoid duplicates
            const postedTaskIds = new Set(
                rawPosts
                    .filter((p: any) => p.task_id || p.task?.id)
                    .map((p: any) => p.task_id || p.task?.id)
            );

            // Note: Rides are now included in posts with post_type='ride', so no need to fetch separately
            // Note: Items are now included in posts with post_type='item' or 'donation', so no need to fetch separately
            // When an item is created, a post is automatically created for it in the backend

            // 4. Fetch Tasks (Match ProfileScreen logic - independent tasks)
            try {
                const { apiService } = require('../utils/apiService');
                const [openTasksRes, progressTasksRes] = await Promise.all([
                    apiService.getTasks({ status: 'open', limit: 20 }),
                    apiService.getTasks({ status: 'in_progress', limit: 20 })
                ]);

                const rawTasks = [
                    ...(openTasksRes.success ? (openTasksRes.data || []) : []),
                    ...(progressTasksRes.success ? (progressTasksRes.data || []) : [])
                ];

                // Map tasks to FeedItems
                rawTasks.forEach((task: any) => {
                    // Check if this task is already in a post
                    if (postedTaskIds.has(task.id)) {
                        return;
                    }

                    // Use actual task ID (UUID) without prefix
                    if (!existingIds.has(task.id)) {
                        const creator = task.creator_details || {};

                        const taskItem: FeedItem = {
                            id: task.id, // Use actual task ID
                            type: 'post', // Show as post
                            subtype: 'task_assignment',
                            title: `יצר/ה משימה חדשה: ${task.title}`,
                            description: task.description || '',
                            thumbnail: null,
                            user: {
                                id: creator.id || task.created_by || 'unknown',
                                name: creator.name || 'Unknown User',
                                avatar: creator.avatar_url || undefined
                            },
                            likes: 0,
                            comments: 0,
                            isLiked: false,
                            timestamp: task.created_at || new Date().toISOString(),
                            taskData: {
                                id: task.id,
                                title: task.title,
                                status: task.status
                            }
                        };
                        allContent.push(taskItem);
                        existingIds.add(task.id);
                    }
                });
            } catch (e) {
                logger.warn('useFeedData', 'Failed to load tasks', { error: e });
            }

            // Sort by timestamp
            allContent.sort((a, b) => {
                return new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime();
            });

            setFeed(allContent);

        } catch (error) {
            logger.error('useFeedData', 'Error loading feed', { error });
            // Don't clear feed on error, maybe show toast
        } finally {
            setLoading(false);
            setRefreshing(false);
        }
    }, [feedMode, currentUser?.id]);

    useEffect(() => {
        loadFeed();
    }, [loadFeed]);

    return {
        feed,
        loading,
        refreshing,
        refresh: () => loadFeed(true),
        loadMore: () => { } // Implement pagination later
    };
};

import { useState } from 'react';
import { Alert, Platform } from 'react-native';
import { apiService } from '../utils/apiService';
import { useUser } from '../stores/userStore';
import { toastService } from '../utils/toastService';
import { useTranslation } from 'react-i18next';

export const usePostDeletion = () => {
    const { selectedUser } = useUser();
    const { t } = useTranslation();
    const [isDeleting, setIsDeleting] = useState(false);

    const canDelete = (postAuthorId: string): boolean => {
        if (!selectedUser) return false;

        // User can delete their own posts
        if (postAuthorId === selectedUser.id) return true;

        // Super admin can delete any post
        if (selectedUser.roles?.includes('super_admin')) return true;

        return false;
    };

    const showDeleteConfirmation = (postType: string): Promise<boolean> => {
        return new Promise((resolve) => {
            const messages = {
                ride: {
                    title: 'מחיקת פוסט טרמפ',
                    message: 'מחיקת הפוסט תמחק גם את הנסיעה ואת כל ההזמנות. האם להמשיך?'
                },
                item: {
                    title: 'מחיקת פוסט פריט',
                    message: 'מחיקת הפוסט תמחק גם את הפריט ואת כל הבקשות. האם להמשיך?'
                },
                donation: {
                    title: 'מחיקת פוסט תרומה',
                    message: 'מחיקת הפוסט תמחק גם את התרומה. האם להמשיך?'
                },
                task_completion: {
                    title: 'מחיקת פוסט משימה',
                    message: 'האם למחוק את הפוסט? (המשימה תישאר)'
                },
                task_assignment: {
                    title: 'מחיקת פוסט משימה',
                    message: 'האם למחוק את הפוסט? (המשימה תישאר)'
                },
                default: {
                    title: 'מחיקת פוסט',
                    message: 'האם למחוק את הפוסט?'
                }
            };

            const config = messages[postType as keyof typeof messages] || messages.default;

            if (Platform.OS === 'web') {
                const confirmed = window.confirm(`${config.title}\n\n${config.message}`);
                resolve(confirmed);
            } else {
                Alert.alert(
                    config.title,
                    config.message,
                    [
                        {
                            text: 'ביטול',
                            style: 'cancel',
                            onPress: () => resolve(false)
                        },
                        {
                            text: 'מחק',
                            style: 'destructive',
                            onPress: () => resolve(true)
                        }
                    ],
                    { cancelable: true }
                );
            }
        });
    };

    const deletePost = async (
        postId: string,
        postType: string,
        onSuccess?: () => void
    ): Promise<boolean> => {
        if (!selectedUser) {
            toastService.showError('יש להתחבר כדי למחוק פוסט');
            return false;
        }

        // Show confirmation dialog
        const confirmed = await showDeleteConfirmation(postType);
        if (!confirmed) return false;

        setIsDeleting(true);

        try {
            const result = await apiService.deletePost(postId, selectedUser.id);

            if (result.success) {
                toastService.showSuccess(
                    result.data?.message || 'הפוסט נמחק בהצלחה'
                );

                // Call success callback
                if (onSuccess) {
                    onSuccess();
                }

                return true;
            } else {
                toastService.showError(
                    result.error || 'שגיאה במחיקת הפוסט'
                );
                return false;
            }
        } catch (error) {
            console.error('Error deleting post:', error);
            toastService.showError('שגיאה במחיקת הפוסט');
            return false;
        } finally {
            setIsDeleting(false);
        }
    };

    return {
        canDelete,
        deletePost,
        isDeleting
    };
};

import { useState, useEffect } from 'react';
import { Share, Alert, Platform } from 'react-native';
import { postsService } from '../utils/postsService';
import { isBookmarked, addBookmark, removeBookmark } from '../utils/bookmarksService';
import { toastService } from '../utils/toastService';
import { logger } from '../utils/loggerService';
import { FeedItem } from '../types/feed';
import { useUser } from '../stores/userStore';

export const usePostInteractions = (item: FeedItem) => {
    // Correct destructuring for useUser
    const { selectedUser: user } = useUser();

    // Local state for optimistic updates
    const [isLiked, setIsLiked] = useState(item.isLiked);
    const [likesCount, setLikesCount] = useState(item.likes);
    const [commentsCount, setCommentsCount] = useState(item.comments);
    const [isBookmarkedState, setIsBookmarkedState] = useState(false);
    const [isLikeLoading, setIsLikeLoading] = useState(false);

    // Sync state if item prop changes (e.g. after refresh)
    useEffect(() => {
        setIsLiked(item.isLiked);
        setLikesCount(item.likes);
        setCommentsCount(item.comments);
    }, [item.isLiked, item.likes, item.comments]);

    // Check bookmark status on mount
    useEffect(() => {
        const checkBookmark = async () => {
            if (item.id && user?.id) {
                const bookmarked = await isBookmarked(user.id, item.id);
                setIsBookmarkedState(bookmarked);
            }
        };
        checkBookmark();
    }, [item.id, user?.id]);

    const handleLike = async () => {
        if (!user || !user.id) {
            toastService.show('Please login to like posts');
            return;
        }

        if (isLikeLoading) return;

        // Optimistic update
        const previousIsLiked = isLiked;
        const previousLikesCount = likesCount;
        const newIsLiked = !isLiked;

        setIsLiked(newIsLiked);
        setLikesCount(prev => newIsLiked ? prev + 1 : Math.max(0, prev - 1));
        setIsLikeLoading(true);

        try {
            logger.debug('usePostInteractions', 'Toggling like', { postId: item.id, newIsLiked });
            // Correct method name: togglePostLike
            const response = await postsService.togglePostLike(item.id, user.id);

            if (!response.success) {
                throw new Error('Failed to toggle like');
            }
        } catch (error) {
            logger.error('usePostInteractions', 'Error toggling like', { error });
            // Revert on error
            setIsLiked(previousIsLiked);
            setLikesCount(previousLikesCount);
            toastService.showError('Failed to update like');
        } finally {
            setIsLikeLoading(false);
        }
    };

    const handleBookmark = async () => {
        if (!user || !user.id) {
            toastService.show('Please login to bookmark posts');
            return;
        }

        try {
            if (isBookmarkedState) {
                await removeBookmark(user.id, item.id);
                setIsBookmarkedState(false);
                toastService.show('Removed from bookmarks');
            } else {
                await addBookmark(user.id, item);
                setIsBookmarkedState(true);
                toastService.show('Added to bookmarks');
            }
        } catch (error) {
            logger.error('usePostInteractions', 'Error toggling bookmark', { error });
            toastService.showError('Failed to update bookmark');
        }
    };

    const handleShare = async () => {
        try {
            const result = await Share.share({
                message: `Check out this post on Karma Community: ${item.title}`,
                // url: `https://karma-community.com/post/${item.id}`, // TODO: Deep linking
            });

            if (result.action === Share.sharedAction) {
                if (result.activityType) {
                    logger.debug('usePostInteractions', 'Shared with activity type', { type: result.activityType });
                } else {
                    logger.debug('usePostInteractions', 'Shared successfully');
                }
            } else if (result.action === Share.dismissedAction) {
                logger.debug('usePostInteractions', 'Share dismissed');
            }
        } catch (error) {
            logger.error('usePostInteractions', 'Error sharing', { error });
            toastService.showError('Failed to share post');
        }
    };

    return {
        isLiked,
        likesCount,
        commentsCount,
        isBookmarked: isBookmarkedState,
        isLikeLoading,
        handleLike,
        handleBookmark,
        handleShare,
        setCommentsCount
    };
};

import { useCallback, useState } from 'react';
import { Platform, ActionSheetIOS, Alert } from 'react-native';
import { useTranslation } from 'react-i18next';
import { FeedItem } from '../types/feed';
import { usePostDeletion } from './usePostDeletion';
import { useUser } from '../stores/userStore';
import { toastService } from '../utils/toastService';
import { Option } from '../components/Feed/OptionsModal';

interface UsePostMenuOptions {
  onDelete?: (postId: string) => void;
  onReport?: (item: FeedItem) => void;
  onEdit?: (item: FeedItem) => void;
  onReopen?: (item: FeedItem) => void;
  onHide?: (item: FeedItem) => void;
}

interface UsePostMenuReturn {
  handleMorePress: (item: FeedItem, measurements?: { x: number, y: number }) => void;
  optionsModalVisible: boolean;
  setOptionsModalVisible: (visible: boolean) => void;
  modalOptions: Option[];
  modalPosition: { x: number, y: number } | undefined;
  reportModalVisible: boolean;
  setReportModalVisible: (visible: boolean) => void;
  selectedPostForReport: FeedItem | null;
  setSelectedPostForReport: (item: FeedItem | null) => void;
}

export const usePostMenu = (options: UsePostMenuOptions = {}): UsePostMenuReturn => {
  const { t } = useTranslation('common');
  const { selectedUser } = useUser();
  const { canDelete, deletePost } = usePostDeletion();

  const [optionsModalVisible, setOptionsModalVisible] = useState(false);
  const [modalOptions, setModalOptions] = useState<Option[]>([]);
  const [modalPosition, setModalPosition] = useState<{ x: number, y: number } | undefined>(undefined);
  const [reportModalVisible, setReportModalVisible] = useState(false);
  const [selectedPostForReport, setSelectedPostForReport] = useState<FeedItem | null>(null);

  // Check if post is closed
  const isPostClosed = useCallback((item: FeedItem): boolean => {
    const status = item.status;
    const subtype = item.subtype || item.type;

    // Tasks: done or archived
    if (subtype === 'task_assignment' || subtype === 'task_completion' || subtype === 'task_post') {
      const taskStatus = item.taskData?.status || status;
      return taskStatus === 'done' || taskStatus === 'archived';
    }

    // Rides: completed or cancelled
    if (subtype === 'ride' || subtype === 'ride_offered' || subtype === 'ride_completed') {
      return status === 'completed' || status === 'cancelled';
    }

    // Items: delivered, completed, or expired
    if (subtype === 'item' || subtype === 'donation') {
      return status === 'delivered' || status === 'completed' || status === 'expired';
    }

    return false;
  }, []);

  const handleMorePress = useCallback((item: FeedItem, measurements?: { x: number, y: number }) => {
    const isOwner = selectedUser?.id === item.user.id;
    const canDeleteThisPost = canDelete(item.user.id);
    const isClosed = isPostClosed(item);

    // Actions
    const handleDelete = () => {
      deletePost(item.id, item.subtype || 'general', () => {
        if (options.onDelete) {
          options.onDelete(item.id);
        }
      });
    };

    const handleReport = () => {
      if (options.onReport) {
        options.onReport(item);
      } else {
        setSelectedPostForReport(item);
        setReportModalVisible(true);
      }
    };

    const handleEdit = () => {
      if (options.onEdit) {
        options.onEdit(item);
      } else {
        toastService.showInfo(t('edit_coming_soon') || 'Edit functionality coming soon!');
      }
    };

    const handleReopen = () => {
      if (options.onReopen) {
        options.onReopen(item);
      } else {
        toastService.showInfo(t('reopen_coming_soon') || 'Reopen functionality coming soon!');
      }
    };

    const handleHide = () => {
      if (options.onHide) {
        options.onHide(item);
      } else {
        toastService.showInfo(t('hide_coming_soon') || 'Hide functionality coming soon!');
      }
    };

    if (Platform.OS === 'ios') {
      const iosOptions = [t('cancel') || 'Cancel'];
      const destructiveButtonIndex: number[] = [];

      // Delete (if has permission)
      if (canDeleteThisPost) {
        iosOptions.push(t('delete') || 'Delete');
        destructiveButtonIndex.push(iosOptions.length - 1);
      }

      // Reopen (if closed and is owner)
      if (isClosed && isOwner) {
        iosOptions.push(t('reopen') || 'Reopen');
      }

      // Edit (if owner)
      if (isOwner) {
        iosOptions.push(t('edit') || 'Edit');
      }

      // Hide (if owner and not closed)
      if (isOwner && !isClosed) {
        iosOptions.push(t('hide') || 'Hide');
      }

      // Report (always show)
      if (!isOwner) {
        iosOptions.push(t('report') || 'Report');
        destructiveButtonIndex.push(iosOptions.length - 1);
      }

      ActionSheetIOS.showActionSheetWithOptions(
        {
          options: iosOptions,
          cancelButtonIndex: 0,
          destructiveButtonIndex,
          title: t('options') || 'Options'
        },
        (buttonIndex) => {
          if (buttonIndex === 0) return; // Cancel

          const selectedOption = iosOptions[buttonIndex];
          if (selectedOption === (t('delete') || 'Delete')) {
            handleDelete();
          } else if (selectedOption === (t('report') || 'Report')) {
            handleReport();
          } else if (selectedOption === (t('edit') || 'Edit')) {
            handleEdit();
          } else if (selectedOption === (t('reopen') || 'Reopen')) {
            handleReopen();
          } else if (selectedOption === (t('hide') || 'Hide')) {
            handleHide();
          }
        }
      );
    } else {
      // Android & Web: Use Custom OptionsModal
      const androidOptions: Option[] = [];

      // Delete (if has permission)
      if (canDeleteThisPost) {
        androidOptions.push({
          label: t('delete') || 'Delete',
          onPress: handleDelete,
          isDestructive: true,
          icon: 'trash-outline'
        });
      }

      // Reopen (if closed and is owner)
      if (isClosed && isOwner) {
        androidOptions.push({
          label: t('reopen') || 'Reopen',
          onPress: handleReopen,
          icon: 'refresh-outline'
        });
      }

      // Edit (if owner)
      if (isOwner) {
        androidOptions.push({
          label: t('edit') || 'Edit',
          onPress: handleEdit,
          icon: 'create-outline'
        });
      }

      // Hide (if owner and not closed)
      if (isOwner && !isClosed) {
        androidOptions.push({
          label: t('hide') || 'Hide',
          onPress: handleHide,
          icon: 'eye-off-outline'
        });
      }

      // Always show report option
      androidOptions.push({
        label: t('report') || 'Report',
        onPress: handleReport,
        isDestructive: true,
        icon: 'flag-outline'
      });

      setModalOptions(androidOptions);
      setModalPosition(measurements);
      setOptionsModalVisible(true);
    }
  }, [selectedUser, canDelete, deletePost, isPostClosed, t, options]);

  return {
    handleMorePress,
    optionsModalVisible,
    setOptionsModalVisible,
    modalOptions,
    modalPosition,
    reportModalVisible,
    setReportModalVisible,
    selectedPostForReport,
    setSelectedPostForReport
  };
};

import { useNavigation } from '@react-navigation/native';
import { useUser } from '../stores/userStore';
import { logger } from '../utils/loggerService';

export const useProfileNavigation = () => {
    const navigation = useNavigation<any>();
    const { selectedUser: currentUser } = useUser();

    const navigateToProfile = (targetUserId: string, targetUserName: string, fromScreen: string = 'Feed') => {
        logger.debug('useProfileNavigation', 'Navigating to profile', {
            targetUserId,
            targetUserName,
            currentUserId: currentUser?.id
        });

        if (!targetUserId) {
            logger.warn('useProfileNavigation', 'Cannot navigate to profile - missing userId');
            return;
        }

        const isOwnProfile = targetUserId === currentUser?.id;

        if (isOwnProfile) {
            _navigateToOwnProfile(navigation, currentUser);
        } else {
            _navigateToUserProfile(navigation, targetUserId, targetUserName);
        }
    };

    return { navigateToProfile };
};

// Helper: Traverse to find BottomNavigator or correct stack for Own Profile
const _navigateToOwnProfile = (navigation: any, currentUser: any) => {
    try {
        logger.debug('useProfileNavigation', 'Attempting navigation to own profile (Tab)');

        // Strategy 1: Direct Tab Navigation if available in root
        // This is often the most reliable for BottomTabs
        try {
            navigation.navigate('ProfileScreen');
            return;
        } catch (err) {
            // Ignore, try next strategy
        }

        // Strategy 2: Find Parent Navigator (BottomTabs)
        let parent = navigation.getParent();
        while (parent) {
            const state = parent.getState();
            if (state?.type === 'tab' || state?.routeNames?.includes('ProfileScreen')) {
                parent.navigate('ProfileScreen');
                return;
            }
            parent = parent.getParent();
        }

        logger.warn('useProfileNavigation', 'Could not find ProfileScreen tab, falling back');
        // Fallback behavior: if we really can't find the tab, we might be in a detached stack.
        // But for the user request, they specifically want the "ProfileMain" (which implies the tab root).

        // If all else fails, forcing a navigate might work if 'ProfileScreen' is registered globally
        navigation.navigate('ProfileScreen');

    } catch (error) {
        logger.error('useProfileNavigation', 'Error navigating to ProfileScreen tab', { error });
        // Absolute fallback to user profile screen if the system is completely broken
        if (currentUser) {
            _navigateToUserProfile(navigation, currentUser.id, currentUser.name || 'My Profile');
        }
    }
};

// Helper: Navigate to generic UserProfileScreen
const _navigateToUserProfile = (navigation: any, userId: string, userName: string) => {
    try {
        // Try to navigate via HomeTabStack first to keep bottom bar
        let bottomNavigator = null;
        let currentNav = navigation;
        let depth = 0;
        const maxDepth = 5;

        while (currentNav && depth < maxDepth) {
            const state = currentNav.getState?.();
            if (state?.routeNames?.includes('HomeScreen')) {
                bottomNavigator = currentNav;
                break;
            }
            const parent = currentNav.getParent?.();
            if (parent) {
                currentNav = parent;
                depth++;
            } else {
                break;
            }
        }

        const params = {
            userId: userId,
            userName: userName,
            characterData: null
        };

        if (bottomNavigator) {
            bottomNavigator.navigate('HomeScreen', {
                screen: 'UserProfileScreen',
                params
            });
            return;
        }

        // Standard navigation
        const parentNavigator = navigation.getParent();
        if (parentNavigator) {
            try {
                parentNavigator.navigate('HomeScreen', {
                    screen: 'UserProfileScreen',
                    params
                });
            } catch (e) {
                parentNavigator.navigate('UserProfileScreen', params);
            }
        } else {
            navigation.navigate('UserProfileScreen', params);
        }

    } catch (error) {
        logger.error('useProfileNavigation', 'Error navigating to UserProfileScreen', { error, userId });
        navigation.navigate('UserProfileScreen', {
            userId: userId,
            userName: userName,
            characterData: null
        });
    }
};

// useScrollPosition.ts
// Hook for preserving scroll position across re-renders
// Works with both ScrollView and FlatList components
// Session-only persistence - position is cleared when app closes

import { useEffect, useRef, useLayoutEffect, useCallback } from 'react';
import { Platform, ScrollView, FlatList } from 'react-native';
import { useFocusEffect } from '@react-navigation/native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useUser } from '../stores/userStore';
import { logger } from '../utils/loggerService';

const LOG_SOURCE = 'useScrollPosition';

// Storage key format: scroll_pos_{screenKey}_{userId}
const getStorageKey = (screenKey: string, userId: string | null): string => {
  const userIdPart = userId || 'guest';
  return `scroll_pos_${screenKey}_${userIdPart}`;
};

// Debounce function to limit save frequency
const createDebouncer = () => {
  let timeout: ReturnType<typeof setTimeout> | null = null;
  return (fn: () => void, delay: number) => {
    if (timeout) {
      clearTimeout(timeout);
    }
    timeout = setTimeout(fn, delay);
  };
};

interface UseScrollPositionOptions {
  enabled?: boolean;
  debounceDelay?: number;
}

/**
 * Hook to preserve scroll position for a screen
 * 
 * @param screenKey - Unique identifier for the screen (e.g., 'AdminMoneyScreen')
 * @param options - Configuration options
 * @returns ref to attach to ScrollView or FlatList component
 * 
 * @example
 * ```tsx
 * const scrollRef = useScrollPosition('AdminMoneyScreen');
 * 
 * <ScrollView ref={scrollRef}>
 *   {content}
 * </ScrollView>
 * ```
 */
export const useScrollPosition = (
  screenKey: string,
  options: UseScrollPositionOptions = {}
): React.RefObject<ScrollView | FlatList> => {
  const { enabled = true, debounceDelay = 200 } = options;
  const { selectedUser } = useUser();
  const scrollRef = useRef<ScrollView | FlatList>(null);
  const debounce = useRef(createDebouncer()).current;
  const isRestoringRef = useRef(false);
  const lastSavedPositionRef = useRef<number>(0);

  // Load saved position when screen gains focus
  useFocusEffect(
    useCallback(() => {
      if (!enabled) {
        return;
      }

      const restorePosition = async () => {
        try {
          const storageKey = getStorageKey(screenKey, selectedUser?.id || null);
          let savedPosition: string | null = null;

          if (Platform.OS === 'web') {
            // Web: synchronous localStorage
            if (typeof window !== 'undefined' && window.localStorage) {
              savedPosition = window.localStorage.getItem(storageKey);
            }
          } else {
            // Native: asynchronous AsyncStorage
            savedPosition = await AsyncStorage.getItem(storageKey);
          }

          if (savedPosition) {
            const position = parseFloat(savedPosition);
            if (!isNaN(position) && position > 0 && scrollRef.current) {
              isRestoringRef.current = true;

              // Small delay to ensure ScrollView is fully rendered
              setTimeout(() => {
                try {
                  if (scrollRef.current) {
                    if ('scrollTo' in scrollRef.current) {
                      // ScrollView
                      scrollRef.current.scrollTo({ y: position, animated: false });
                    } else if ('scrollToOffset' in scrollRef.current) {
                      // FlatList
                      (scrollRef.current as FlatList<any>).scrollToOffset({
                        offset: position,
                        animated: false,
                      });
                    }
                    logger.debug(LOG_SOURCE, 'Scroll position restored', {
                      screenKey,
                      position,
                    });
                  }
                } catch (error) {
                  logger.error(LOG_SOURCE, 'Error restoring scroll position', { error });
                } finally {
                  // Reset flag after a short delay
                  setTimeout(() => {
                    isRestoringRef.current = false;
                  }, 100);
                }
              }, 100);
            }
          }
        } catch (error) {
          logger.error(LOG_SOURCE, 'Error loading scroll position', { error });
        }
      };

      restorePosition();
    }, [screenKey, selectedUser?.id, enabled])
  );

  // Save position when scrolling
  useEffect(() => {
    if (!enabled || !scrollRef.current) {
      return;
    }

    // For ScrollView - attach scroll event handler
    if ('scrollTo' in scrollRef.current) {
      const scrollView = scrollRef.current as ScrollView;

      // Note: ScrollView's onScroll event needs to be passed as a prop
      // We'll need to handle this differently - see usage example
      // For now, we'll save on blur/focus change
    }

    return () => {
      // Cleanup if needed
    };
  }, [enabled, scrollRef.current]);

  // Save position when screen loses focus
  useFocusEffect(
    useCallback(() => {
      return () => {
        // Cleanup function - called when screen loses focus
        if (!enabled || isRestoringRef.current) {
          return;
        }

        const savePosition = async () => {
          try {
            if (!scrollRef.current) {
              return;
            }

            let position: number | null = null;

            // Try to get current scroll position
            // Note: ScrollView and FlatList don't expose scroll position directly
            // This is a limitation - we'll need to track it via onScroll callback
            // For now, we save the last known position

            if (lastSavedPositionRef.current > 0) {
              position = lastSavedPositionRef.current;
            }

            if (position !== null && position > 0) {
              const storageKey = getStorageKey(screenKey, selectedUser?.id || null);
              const positionString = position.toString();

              debounce(() => {
                if (Platform.OS === 'web') {
                  // Web: synchronous localStorage
                  if (typeof window !== 'undefined' && window.localStorage) {
                    window.localStorage.setItem(storageKey, positionString);
                  }
                } else {
                  // Native: asynchronous AsyncStorage
                  AsyncStorage.setItem(storageKey, positionString).catch((error) => {
                    logger.error(LOG_SOURCE, 'Failed to save scroll position', { error });
                  });
                }
              }, debounceDelay);

              logger.debug(LOG_SOURCE, 'Scroll position saved', {
                screenKey,
                position,
              });
            }
          } catch (error) {
            logger.error(LOG_SOURCE, 'Error saving scroll position', { error });
          }
        };

        savePosition();
      };
    }, [screenKey, selectedUser?.id, enabled, debounceDelay])
  );

  return scrollRef;
};

/**
 * Hook that returns both ref and onScroll handler for ScrollView
 * Use this version when you need full control over scroll events
 * 
 * @param screenKey - Unique identifier for the screen
 * @param options - Configuration options
 * @returns { ref, onScroll } - ref to attach and onScroll handler
 */
export const useScrollPositionWithHandler = (
  screenKey: string,
  options: UseScrollPositionOptions = {}
): {
  ref: React.RefObject<ScrollView | FlatList>;
  onScroll: (event: any) => void;
} => {
  const { enabled = true, debounceDelay = 200 } = options;
  const { selectedUser } = useUser();
  const scrollRef = useRef<ScrollView | FlatList>(null);
  const debounce = useRef(createDebouncer()).current;
  const lastSavedPositionRef = useRef<number>(0);

  const handleScroll = useCallback(
    (event: any) => {
      if (!enabled) {
        return;
      }

      const {
        nativeEvent: { contentOffset },
      } = event;

      const position = contentOffset?.y || 0;
      lastSavedPositionRef.current = position;

      // Debounce the save operation
      debounce(() => {
        const storageKey = getStorageKey(screenKey, selectedUser?.id || null);
        const positionString = position.toString();

        try {
          if (Platform.OS === 'web') {
            // Web: synchronous localStorage
            if (typeof window !== 'undefined' && window.localStorage) {
              window.localStorage.setItem(storageKey, positionString);
            }
          } else {
            // Native: asynchronous AsyncStorage
            AsyncStorage.setItem(storageKey, positionString).catch((error) => {
              logger.error(LOG_SOURCE, 'Failed to save scroll position', { error });
            });
          }

          logger.debug(LOG_SOURCE, 'Scroll position saved during scroll', {
            screenKey,
            position,
          });
        } catch (error) {
          logger.error(LOG_SOURCE, 'Error saving scroll position during scroll', { error });
        }
      }, debounceDelay);
    },
    [screenKey, selectedUser?.id, enabled, debounceDelay, debounce]
  );

  // Load saved position when screen gains focus
  useFocusEffect(
    useCallback(() => {
      if (!enabled) {
        return;
      }

      const restorePosition = async () => {
        try {
          const storageKey = getStorageKey(screenKey, selectedUser?.id || null);
          let savedPosition: string | null = null;

          if (Platform.OS === 'web') {
            if (typeof window !== 'undefined' && window.localStorage) {
              savedPosition = window.localStorage.getItem(storageKey);
            }
          } else {
            savedPosition = await AsyncStorage.getItem(storageKey);
          }

          if (savedPosition) {
            const position = parseFloat(savedPosition);
            if (!isNaN(position) && position > 0 && scrollRef.current) {
              setTimeout(() => {
                try {
                  if (scrollRef.current) {
                    if ('scrollTo' in scrollRef.current) {
                      scrollRef.current.scrollTo({ y: position, animated: false });
                    } else if ('scrollToOffset' in scrollRef.current) {
                      (scrollRef.current as FlatList<any>).scrollToOffset({
                        offset: position,
                        animated: false,
                      });
                    }
                    logger.debug(LOG_SOURCE, 'Scroll position restored', {
                      screenKey,
                      position,
                    });
                  }
                } catch (error) {
                  logger.error(LOG_SOURCE, 'Error restoring scroll position', { error });
                }
              }, 100);
            }
          }
        } catch (error) {
          logger.error(LOG_SOURCE, 'Error loading scroll position', { error });
        }
      };

      restorePosition();
    }, [screenKey, selectedUser?.id, enabled])
  );

  return {
    ref: scrollRef,
    onScroll: handleScroll,
  };
};

