            : `האם אתה בטוח שברצונך להפוך את ${user.name || user.email} למנהל תחתיך?`;

        console.log('[AdminAdminsScreen] 📢 Showing Alert.alert:', { title, message });

        Alert.alert(title, message, [
            { 
                text: 'ביטול', 
                style: 'cancel',
                onPress: () => {
                    console.log('[AdminAdminsScreen] ❌ User cancelled');
                }
            },
            {
                text: 'אישור',
