import { FontSizes } from '../globals/constants';
import { db } from '../utils/databaseService';
import { useUser } from '../stores/userStore';

type OrgApplication = {
  id: string;
  orgName: string;
  orgType: string;
  registrationNumber?: string;
  contactName: string;
  contactEmail: string;
  contactPhone: string;
  website?: string;
  city?: string;
  activityAreas: string[];
  needs: string;
  offering: string;
  description: string;
  status: 'pending' | 'approved' | 'rejected';
  createdAt: string;
  updatedAt: string;
  _ownerPartition?: string; // for admin queue
};

export default function AdminOrgApprovalsScreen() {
  const { t } = useTranslation(['auth', 'common']);
  const { selectedUser } = useUser();
  const [items, setItems] = useState<OrgApplication[]>([]);
  const [refreshing, setRefreshing] = useState(false);

  const isAdmin = (selectedUser?.roles || []).includes('admin');

  const load = useCallback(async () => {
    try {
      setRefreshing(true);
      const data = await db.listOrgApplications('admin_org_queue');
      setItems((data as any[]) as OrgApplication[]);
    } catch (e) {

      console.error('admin load error', e);
    } finally {
      setRefreshing(false);
    }
  }, []);

  useEffect(() => {
    load();
  }, [load]);

  const updateStatus = async (app: OrgApplication, status: 'approved' | 'rejected') => {
    try {
      const owner = app._ownerPartition || app.contactEmail.toLowerCase();
      await db.updateOrgApplication(owner, app.id, { status, updatedAt: new Date().toISOString() });
      await db.updateOrgApplication('admin_org_queue', app.id, { status, updatedAt: new Date().toISOString() });
      if (status === 'approved') {
        // create organization record keyed by owner partition
        await db.createOrganization(owner, app.id, {
          id: app.id,
          name: app.orgName,
          type: app.orgType,
          registrationNumber: app.registrationNumber,
          contactName: app.contactName,
          contactEmail: app.contactEmail,
          contactPhone: app.contactPhone,
          website: app.website,
          city: app.city,
          activityAreas: app.activityAreas,
          createdAt: app.createdAt,
          updatedAt: new Date().toISOString(),
          status: 'active',
        });
      }
      Alert.alert(
        status === 'approved' ? (t('common:confirm') || 'אישור') : (t('common:done') || 'סיום'),
        status === 'approved' ? 'הבקשה אושרה' : 'הבקשה נדחתה'
      );
      load();
    } catch (e) {
      Alert.alert('שגיאה', 'עדכון הסטטוס נכשל');
    }
  };

  const renderItem = ({ item }: { item: OrgApplication }) => (
    <View style={styles.card}>
      <View style={styles.rowBetween}>
        <Text style={styles.title}>{item.orgName}</Text>
        <Text style={[styles.status, item.status === 'pending' ? styles.pending : item.status === 'approved' ? styles.approved : styles.rejected]}>
          {item.status}
        </Text>
      </View>
      <Text style={styles.sub}>{item.orgType}{item.city ? ` · ${item.city}` : ''}</Text>
      <Text style={styles.body}>{item.description}</Text>
      <View style={styles.actions}>
        <TouchableOpacity style={[styles.btn, styles.reject]} onPress={() => updateStatus(item, 'rejected')}>
          <Text style={styles.btnText}>דחייה</Text>
        </TouchableOpacity>
        <TouchableOpacity style={[styles.btn, styles.approve]} onPress={() => updateStatus(item, 'approved')}>
          <Text style={styles.btnText}>אישור</Text>
        </TouchableOpacity>
      </View>
    </View>
  );

  if (!isAdmin) {
    return (
      <View style={styles.center}>
        <Text style={styles.body}>אין לך הרשאות לצפות בדף זה</Text>
      </View>
    );
  }

  return (
    <FlatList
      style={styles.container}
      contentContainerStyle={{
        padding: 16,
        flexGrow: 1,
        minHeight: '150%' // Ensure content is always scrollable
      }}
      data={items}
      keyExtractor={(it) => it.id}
      renderItem={renderItem}
      refreshControl={<RefreshControl refreshing={refreshing} onRefresh={load} />}
    />
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, backgroundColor: colors.background },
  center: { flex: 1, alignItems: 'center', justifyContent: 'center' },
  card: { backgroundColor: colors.backgroundSecondary, padding: 12, borderRadius: 12, marginBottom: 12, borderWidth: 1, borderColor: colors.border },
  rowBetween: { flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' },
  title: { fontSize: FontSizes.medium, fontWeight: '700', color: colors.textPrimary },
  sub: { fontSize: FontSizes.small, color: colors.textSecondary, marginBottom: 6 },
  body: { fontSize: FontSizes.body, color: colors.textPrimary },
  status: { fontSize: FontSizes.small, fontWeight: '700' },
  pending: { color: colors.warning },
  approved: { color: colors.success },
  rejected: { color: colors.error },
  actions: { flexDirection: 'row', gap: 8, marginTop: 10, justifyContent: 'flex-end' },
  btn: { paddingVertical: 8, paddingHorizontal: 12, borderRadius: 10 },
  approve: { backgroundColor: colors.primary },
  reject: { backgroundColor: colors.error },
  btnText: { color: colors.white, fontWeight: '700' },
});

import React, { useState, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  SafeAreaView,
  TouchableOpacity,
  Modal,
  TextInput,
  Alert,
  ScrollView,
  RefreshControl,
  ActivityIndicator,
} from 'react-native';
import { NavigationProp, useRoute } from '@react-navigation/native';
import { Ionicons } from '@expo/vector-icons';
import colors from '../globals/colors';
import { FontSizes, LAYOUT_CONSTANTS } from '../globals/constants';
import { AdminStackParamList } from '../globals/types';
import { useUser } from '../stores/userStore';
import { logger } from '../utils/loggerService';
import { apiService } from '../utils/apiService';

interface AdminPeopleScreenProps {
  navigation: NavigationProp<AdminStackParamList>;
}

interface CommunityMember {
  id: string;
  name: string;
  role: string; // התפקיד/התרומה שלו לקהילה
  description?: string;
  contact_info?: {
    email?: string;
    phone?: string;
    [key: string]: any;
  };
  status: 'active' | 'inactive';
  created_by?: string;
  created_at: string;
  updated_at: string;
}

interface MemberFormData {
  name: string;
  role: string;
  description: string;
  email: string;
  phone: string;
  status: 'active' | 'inactive';
}

const LOG_SOURCE = 'AdminPeopleScreen';

import { useAdminProtection } from '../hooks/useAdminProtection';

export default function AdminPeopleScreen({ navigation }: AdminPeopleScreenProps) {
  const route = useRoute();
  const routeParams = (route.params as any) || {};
  const viewOnly = routeParams?.viewOnly === true;
  useAdminProtection(true);
  const { selectedUser, isAdmin } = useUser();
  const [membersList, setMembersList] = useState<CommunityMember[]>([]);
  const [isModalVisible, setIsModalVisible] = useState(false);
  const [isEditMode, setIsEditMode] = useState(false);
  const [editingMemberId, setEditingMemberId] = useState<string | null>(null);
  const [formData, setFormData] = useState<MemberFormData>({
    name: '',
    role: '',
    description: '',
    email: '',
    phone: '',
    status: 'active',
  });
  const [isLoading, setIsLoading] = useState(false);
  const [isMutating, setIsMutating] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<'all' | 'active' | 'inactive'>('all');

  useEffect(() => {
    logger.info(LOG_SOURCE, 'Initializing admin people screen');
    loadMembers();
  }, [statusFilter, searchQuery]);

  const loadMembers = async () => {
    logger.info(LOG_SOURCE, 'Loading community members list');
    try {
      setIsLoading(true);
      const filters: { status?: 'active' | 'inactive'; search?: string } = {};

      if (statusFilter !== 'all') {
        filters.status = statusFilter;
      }

      if (searchQuery.trim()) {
        filters.search = searchQuery.trim();
      }

      const response = await apiService.getCommunityMembers(filters);

      if (response.success && Array.isArray(response.data)) {
        setMembersList(response.data);
        logger.info(LOG_SOURCE, 'Members loaded successfully', {
          count: response.data.length,
        });
      } else {
        logger.warn(LOG_SOURCE, 'Failed to load members', { response });
        setMembersList([]);
      }
    } catch (error) {
      logger.error(LOG_SOURCE, 'Error loading members', { error });
      Alert.alert('שגיאה', 'לא ניתן היה לטעון את רשימת האנשים');
      setMembersList([]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleAddMember = () => {
    logger.info(LOG_SOURCE, 'Opening add member modal');
    setIsEditMode(false);
    setEditingMemberId(null);
    setFormData({
      name: '',
      role: '',
      description: '',
      email: '',
      phone: '',
      status: 'active',
    });
    setIsModalVisible(true);
  };

  const handleEditMember = (member: CommunityMember) => {
    logger.info(LOG_SOURCE, 'Opening edit member modal', { memberId: member.id });
    setIsEditMode(true);
    setEditingMemberId(member.id);
    setFormData({
      name: member.name || '',
      role: member.role || '',
      description: member.description || '',
      email: member.contact_info?.email || '',
      phone: member.contact_info?.phone || '',
      status: member.status || 'active',
    });
    setIsModalVisible(true);
  };

  const handleDeleteMember = (member: CommunityMember) => {
    Alert.alert(
      'מחיקת רשומה',
      `האם אתה בטוח שברצונך למחוק את ${member.name}?`,
      [
        { text: 'ביטול', style: 'cancel' },
        {
          text: 'מחק',
          style: 'destructive',
          onPress: async () => {
            try {
              setIsMutating(true);
              logger.info(LOG_SOURCE, 'Deleting member', { memberId: member.id });
              const response = await apiService.deleteCommunityMember(member.id);

              if (response.success) {
                logger.info(LOG_SOURCE, 'Member deleted successfully');
                await loadMembers();
                Alert.alert('בוצע', 'הרשומה נמחקה בהצלחה');
              } else {
                throw new Error(response.error || 'Failed to delete member');
              }
            } catch (error) {
              logger.error(LOG_SOURCE, 'Error deleting member', { error });
              Alert.alert('שגיאה', 'לא ניתן היה למחוק את הרשומה');
            } finally {
              setIsMutating(false);
            }
          },
        },
      ]
    );
  };

  const handleSaveMember = async () => {
    if (!formData.name.trim() || !formData.role.trim()) {
      Alert.alert('שגיאה', 'שם ותפקיד הם שדות חובה');
      return;
    }

    try {
      setIsMutating(true);
      logger.info(LOG_SOURCE, isEditMode ? 'Updating member' : 'Creating member', {
        isEditMode,
        memberId: editingMemberId,
      });

      const memberData: any = {
        name: formData.name.trim(),
        role: formData.role.trim(),
        description: formData.description.trim() || undefined,
        status: formData.status,
        contact_info: {},
      };

      if (formData.email.trim()) {
        memberData.contact_info.email = formData.email.trim();
      }
      if (formData.phone.trim()) {
        memberData.contact_info.phone = formData.phone.trim();
      }

      if (Object.keys(memberData.contact_info).length === 0) {
        memberData.contact_info = undefined;
      }

      if (selectedUser?.id) {
        memberData.created_by = selectedUser.id;
      }

      let response;
      if (isEditMode && editingMemberId) {
        response = await apiService.updateCommunityMember(editingMemberId, memberData);
      } else {
        response = await apiService.createCommunityMember(memberData);
      }

      if (response.success) {
        logger.info(LOG_SOURCE, 'Member saved successfully');
        setIsModalVisible(false);
        await loadMembers();
        Alert.alert('בוצע', isEditMode ? 'הרשומה עודכנה בהצלחה' : 'הרשומה נוספה בהצלחה');
      } else {
        throw new Error(response.error || 'Failed to save member');
      }
    } catch (error) {
      logger.error(LOG_SOURCE, 'Error saving member', { error });
      Alert.alert('שגיאה', 'לא ניתן היה לשמור את הרשומה');
    } finally {
      setIsMutating(false);
    }
  };

  const formatDate = (dateString: string) => {
    try {
      const date = new Date(dateString);
      return date.toLocaleDateString('he-IL', {
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
      });
    } catch {
      return dateString;
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.header}>
        <Text style={styles.title}>ניהול אנשים</Text>
        <TouchableOpacity
          style={styles.addButton}
          onPress={viewOnly ? undefined : handleAddMember}
          disabled={viewOnly || isMutating}
        >
          <Ionicons name="add" size={24} color="white" />
          <Text style={styles.addButtonText}>הוסף רשומה</Text>
        </TouchableOpacity>
      </View>

      {/* Filters */}
      <View style={styles.filtersContainer}>
        <View style={styles.searchContainer}>
          <Ionicons name="search" size={20} color={colors.textSecondary} style={styles.searchIcon} />
          <TextInput
            style={styles.searchInput}
            value={searchQuery}
            onChangeText={setSearchQuery}
            placeholder="חפש לפי שם, תפקיד או תיאור..."
            placeholderTextColor={colors.textTertiary}
          />
          {searchQuery.length > 0 && (
            <TouchableOpacity onPress={() => setSearchQuery('')} style={styles.clearButton}>
              <Ionicons name="close-circle" size={20} color={colors.textSecondary} />
            </TouchableOpacity>
          )}
        </View>

        <View style={styles.statusFilterContainer}>
          <TouchableOpacity
            style={[styles.filterButton, statusFilter === 'all' && styles.filterButtonActive]}
            onPress={() => setStatusFilter('all')}
          >
            <Text style={[styles.filterButtonText, statusFilter === 'all' && styles.filterButtonTextActive]}>
              הכל
            </Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={[styles.filterButton, statusFilter === 'active' && styles.filterButtonActive]}
            onPress={() => setStatusFilter('active')}
          >
            <Text style={[styles.filterButtonText, statusFilter === 'active' && styles.filterButtonTextActive]}>
              פעיל
            </Text>
          </TouchableOpacity>
          <TouchableOpacity
            style={[styles.filterButton, statusFilter === 'inactive' && styles.filterButtonActive]}
            onPress={() => setStatusFilter('inactive')}
          >
            <Text style={[styles.filterButtonText, statusFilter === 'inactive' && styles.filterButtonTextActive]}>
              לא פעיל
            </Text>
          </TouchableOpacity>
        </View>
      </View>

      {/* Members List */}
      {isLoading ? (
        <View style={styles.loadingContainer}>
          <ActivityIndicator size="large" color={colors.primary} />
          <Text style={styles.loadingText}>טוען...</Text>
        </View>
      ) : membersList.length === 0 ? (
        <View style={styles.emptyContainer}>
          <Ionicons name="people-outline" size={64} color={colors.textSecondary} />
          <Text style={styles.emptyText}>אין רשומות</Text>
          <Text style={styles.emptySubtext}>
            {searchQuery || statusFilter !== 'all'
              ? 'לא נמצאו רשומות התואמות לחיפוש'
              : 'לחץ על "הוסף רשומה" כדי להתחיל'}
          </Text>
        </View>
      ) : (
        <ScrollView
          style={styles.listContainer}
          contentContainerStyle={{
            flexGrow: 1,
            minHeight: '150%' // Ensure content is always scrollable
          }}
          refreshControl={
            <RefreshControl refreshing={isLoading} onRefresh={loadMembers} />
          }
        >
          {membersList.map((member) => (
            <View key={member.id} style={styles.memberCard}>
              <View style={styles.memberHeader}>
                <View style={styles.memberInfo}>
                  <Text style={styles.memberName}>{member.name}</Text>
                  <View style={styles.memberMeta}>
                    <View style={[styles.statusBadge, member.status === 'active' ? styles.statusBadgeActive : styles.statusBadgeInactive]}>
                      <Text style={[styles.statusText, member.status === 'active' ? styles.statusTextActive : styles.statusTextInactive]}>
                        {member.status === 'active' ? 'פעיל' : 'לא פעיל'}
                      </Text>
                    </View>
                    <Text style={styles.memberDate}>{formatDate(member.created_at)}</Text>
                  </View>
                </View>
                <View style={styles.memberActions}>
                  {!viewOnly && (
                    <>
                      <TouchableOpacity
                        style={styles.actionButton}
                        onPress={() => handleEditMember(member)}
                        disabled={isMutating}
                      >
                        <Ionicons name="create-outline" size={20} color={colors.primary} />
                      </TouchableOpacity>
                      <TouchableOpacity
                        style={styles.actionButton}
                        onPress={() => handleDeleteMember(member)}
                        disabled={isMutating}
                      >
                        <Ionicons name="trash-outline" size={20} color={colors.error} />
                      </TouchableOpacity>
                    </>
                  )}
                </View>
              </View>

              <View style={styles.memberDetails}>
                <View style={styles.detailRow}>
                  <Ionicons name="briefcase-outline" size={16} color={colors.textSecondary} />
                  <Text style={styles.detailLabel}>תפקיד/תרומה:</Text>
                  <Text style={styles.detailValue}>{member.role}</Text>
                </View>

                {member.description && (
                  <View style={styles.detailRow}>
                    <Ionicons name="document-text-outline" size={16} color={colors.textSecondary} />
                    <Text style={styles.detailValue} numberOfLines={2}>{member.description}</Text>
                  </View>
                )}

                {(member.contact_info?.email || member.contact_info?.phone) && (
                  <View style={styles.contactInfo}>
                    {member.contact_info?.email && (
                      <View style={styles.detailRow}>
                        <Ionicons name="mail-outline" size={16} color={colors.textSecondary} />
                        <Text style={styles.detailValue}>{member.contact_info.email}</Text>
                      </View>
                    )}
                    {member.contact_info?.phone && (
                      <View style={styles.detailRow}>
                        <Ionicons name="call-outline" size={16} color={colors.textSecondary} />
                        <Text style={styles.detailValue}>{member.contact_info.phone}</Text>
                      </View>
                    )}
                  </View>
                )}
              </View>
            </View>
          ))}
        </ScrollView>
      )}

      {/* Add/Edit Modal */}
      <Modal
        visible={isModalVisible && !viewOnly}
        animationType="slide"
        transparent={true}
        onRequestClose={() => setIsModalVisible(false)}
      >
        <View style={styles.modalOverlay}>
          <View style={styles.modalContent}>
            <View style={styles.modalHeader}>
              <Text style={styles.modalTitle}>
                {isEditMode ? 'ערוך רשומה' : 'הוסף רשומה חדשה'}
              </Text>
              <TouchableOpacity
                onPress={() => setIsModalVisible(false)}
                style={styles.closeButton}
                disabled={isMutating}
              >
                <Ionicons name="close" size={24} color={colors.textPrimary} />
              </TouchableOpacity>
            </View>

            <ScrollView style={styles.modalBody} showsVerticalScrollIndicator={false}>
              <View style={styles.formGroup}>
                <Text style={styles.label}>שם *</Text>
                <TextInput
                  style={styles.input}
                  value={formData.name}
                  onChangeText={(text) => setFormData({ ...formData, name: text })}
                  placeholder="הזן שם"
                  placeholderTextColor={colors.textTertiary}
                />
              </View>

              <View style={styles.formGroup}>
                <Text style={styles.label}>תפקיד/תרומה לקהילה *</Text>
                <TextInput
                  style={styles.input}
                  value={formData.role}
                  onChangeText={(text) => setFormData({ ...formData, role: text })}
                  placeholder="הזן תפקיד או תרומה"
                  placeholderTextColor={colors.textTertiary}
                />
              </View>

              <View style={styles.formGroup}>
                <Text style={styles.label}>תיאור</Text>
                <TextInput
                  style={[styles.input, styles.textArea]}
                  value={formData.description}
                  onChangeText={(text) => setFormData({ ...formData, description: text })}
                  placeholder="תיאור נוסף על התרומה (אופציונלי)"
                  placeholderTextColor={colors.textTertiary}
                  multiline
                  numberOfLines={4}
                  textAlignVertical="top"
                />
              </View>

              <View style={styles.formGroup}>
                <Text style={styles.label}>אימייל</Text>
                <TextInput
                  style={styles.input}
                  value={formData.email}
                  onChangeText={(text) => setFormData({ ...formData, email: text })}
                  placeholder="אימייל (אופציונלי)"
                  placeholderTextColor={colors.textTertiary}
                  keyboardType="email-address"
                  autoCapitalize="none"
                />
              </View>

              <View style={styles.formGroup}>
                <Text style={styles.label}>טלפון</Text>
                <TextInput
                  style={styles.input}
                  value={formData.phone}
                  onChangeText={(text) => setFormData({ ...formData, phone: text })}
                  placeholder="טלפון (אופציונלי)"
                  placeholderTextColor={colors.textTertiary}
                  keyboardType="phone-pad"
                />
              </View>

              <View style={styles.formGroup}>
                <Text style={styles.label}>סטטוס</Text>
                <View style={styles.statusSelector}>
                  <TouchableOpacity
                    style={[
                      styles.statusOption,
                      formData.status === 'active' && styles.statusOptionActive,
                    ]}
                    onPress={() => setFormData({ ...formData, status: 'active' })}
                  >
                    <Text
                      style={[
                        styles.statusOptionText,
                        formData.status === 'active' && styles.statusOptionTextActive,
                      ]}
                    >
                      פעיל
                    </Text>
                  </TouchableOpacity>
                  <TouchableOpacity
                    style={[
                      styles.statusOption,
                      formData.status === 'inactive' && styles.statusOptionActive,
                    ]}
                    onPress={() => setFormData({ ...formData, status: 'inactive' })}
                  >
                    <Text
                      style={[
                        styles.statusOptionText,
                        formData.status === 'inactive' && styles.statusOptionTextActive,
                      ]}
                    >
                      לא פעיל
                    </Text>
                  </TouchableOpacity>
                </View>
              </View>

              <TouchableOpacity
                style={[styles.saveButton, isMutating && styles.saveButtonDisabled]}
                onPress={handleSaveMember}
                disabled={isMutating}
              >
                {isMutating ? (
                  <ActivityIndicator size="small" color="white" />
                ) : (
                  <Text style={styles.saveButtonText}>
                    {isEditMode ? 'עדכן' : 'שמור'}
                  </Text>
                )}
              </TouchableOpacity>
            </ScrollView>
          </View>
        </View>
      </Modal>
    </SafeAreaView>
  );
}

