  try {
    await db.removeFollower(followingId, followerId);

    await db.removeFollowing(followerId, followingId);

    // Update follow counts for both users
    await updateFollowCounts(followerId);
    await updateFollowCounts(followingId);

    return true;
  } catch (error) {
