// navigationPersistence.ts
// Utility for saving and loading React Navigation state
// Supports both web (localStorage) and native (AsyncStorage)
// Session-only persistence - state is cleared when app closes
// Now includes validation and versioning

import { Platform } from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { NavigationState } from '@react-navigation/native';
import { logger } from './loggerService';
import { validateNavigationState, cleanNavigationState, checkNavigationStateVersion } from './navigationStateValidator';
import { CURRENT_NAVIGATION_STATE_VERSION } from '../types/navigation';

const LOG_SOURCE = 'NavigationPersistence';

// Storage key format: nav_state_{mode}_{userId}_{platform}
const getStorageKey = (mode: string, userId: string | null, platform: string): string => {
  const userIdPart = userId || 'guest';
  return `nav_state_${mode}_${userIdPart}_${platform}`;
};

// Debounce function to limit save frequency
let saveTimeout: ReturnType<typeof setTimeout> | null = null;
const DEBOUNCE_DELAY = 300; // ms

/**
 * Save navigation state to persistent storage
 * Uses debouncing to avoid excessive I/O operations
 */
export const saveNavigationState = (
  state: NavigationState | undefined,
  mode: string,
  userId: string | null
): void => {
  if (!state) {
    return;
  }

  // Clear existing timeout
  if (saveTimeout) {
    clearTimeout(saveTimeout);
  }

  // Debounce the save operation
  saveTimeout = setTimeout(() => {
    try {
      // Validate state before saving
      const validation = validateNavigationState(state);
      if (!validation.valid) {
        logger.warn(LOG_SOURCE, 'Navigation state validation failed, not saving', {
          errors: validation.errors,
          warnings: validation.warnings,
        });
        return;
      }

      // Check version compatibility
      const versionCheck = checkNavigationStateVersion(state);
      if (!versionCheck.compatible) {
        logger.warn(LOG_SOURCE, 'Navigation state version incompatible, not saving', {
          error: versionCheck.error,
        });
        return;
      }

      // Clean state before saving
      const cleanedState = cleanNavigationState(state);
      if (!cleanedState) {
        logger.warn(LOG_SOURCE, 'Navigation state cleaning failed, not saving');
        return;
      }

      // Add version to state metadata
      const stateWithVersion = {
        ...cleanedState,
        _metadata: {
          version: CURRENT_NAVIGATION_STATE_VERSION,
          savedAt: new Date().toISOString(),
          mode,
          userId,
        },
      };

      const storageKey = getStorageKey(mode, userId, Platform.OS);
      const stateString = JSON.stringify(stateWithVersion);

      if (Platform.OS === 'web') {
        // Web: synchronous localStorage
        if (typeof window !== 'undefined' && window.localStorage) {
          window.localStorage.setItem(storageKey, stateString);
          logger.debug(LOG_SOURCE, 'Navigation state saved to localStorage', {
            key: storageKey,
            stateSize: stateString.length,
            version: CURRENT_NAVIGATION_STATE_VERSION,
          }, { periodic: true });
        }
      } else {
        // Native: asynchronous AsyncStorage
        AsyncStorage.setItem(storageKey, stateString).catch((error) => {
          logger.error(LOG_SOURCE, 'Failed to save navigation state to AsyncStorage', { error });
        });
        logger.debug(LOG_SOURCE, 'Navigation state saved to AsyncStorage', {
          key: storageKey,
          stateSize: stateString.length,
          version: CURRENT_NAVIGATION_STATE_VERSION,
        }, { periodic: true });
      }
    } catch (error) {
      logger.error(LOG_SOURCE, 'Error saving navigation state', { error });
    }
  }, DEBOUNCE_DELAY);
};

/**
 * Recursively checks if navigation state contains UserProfileScreen as active route
 * This helps prevent loading state that would lead to "user not found" screen
 */
const containsActiveUserProfileScreen = (state: NavigationState): boolean => {
  if (!state || !state.routes || state.routes.length === 0) {
    return false;
  }

  const activeRoute = state.routes[state.index || 0];
  if (!activeRoute) {
    return false;
  }

  // Check if current route is UserProfileScreen
  if (activeRoute.name === 'UserProfileScreen') {
    return true;
  }

  // Recursively check nested states
  if (activeRoute.state) {
    return containsActiveUserProfileScreen(activeRoute.state as any);
  }

  return false;
};

/**
 * Load navigation state from persistent storage
 * Returns null if no state is found or if there's an error
 */
export const loadNavigationState = async (
  mode: string,
  userId: string | null
): Promise<NavigationState | null> => {
  try {
    const storageKey = getStorageKey(mode, userId, Platform.OS);
    let stateString: string | null = null;

    if (Platform.OS === 'web') {
      // Web: synchronous localStorage
      if (typeof window !== 'undefined' && window.localStorage) {
        stateString = window.localStorage.getItem(storageKey);
      }
    } else {
      // Native: asynchronous AsyncStorage
      stateString = await AsyncStorage.getItem(storageKey);
    }

    if (!stateString) {
      logger.debug(LOG_SOURCE, 'No saved navigation state found', { key: storageKey });
      return null;
    }

    let state: NavigationState;
    try {
      state = JSON.parse(stateString) as NavigationState;
    } catch (parseError) {
      logger.error(LOG_SOURCE, 'Failed to parse navigation state', { error: parseError });
      // Clear corrupted state
      await clearNavigationState(mode, userId);
      return null;
    }

    // Remove metadata if present (it's not part of NavigationState type)
    const metadata = (state as any)._metadata;
    if (metadata) {
      const { _metadata: __metadata, ...stateWithoutMetadata } = state as any;
      state = stateWithoutMetadata as NavigationState;
    }

    // Check if state contains active UserProfileScreen - if so, don't load it
    // This prevents opening "user not found" screen after data reset
    if (containsActiveUserProfileScreen(state)) {
      logger.warn(LOG_SOURCE, 'Navigation state contains active UserProfileScreen, clearing to prevent "user not found" screen', {
        key: storageKey,
        savedUserId: metadata?.userId,
        currentUserId: userId,
      });
      // Clear state with active UserProfileScreen
      await clearNavigationState(mode, userId);
      return null;
    }

    // Validate loaded state
    const validation = validateNavigationState(state);
    if (!validation.valid) {
      logger.warn(LOG_SOURCE, 'Loaded navigation state is invalid, clearing it', {
        errors: validation.errors,
        warnings: validation.warnings,
      });
      // Clear invalid state
      await clearNavigationState(mode, userId);
      return null;
    }

    // Check version compatibility
    const versionCheck = checkNavigationStateVersion(state);
    if (!versionCheck.compatible) {
      logger.warn(LOG_SOURCE, 'Loaded navigation state version is incompatible, clearing it', {
        error: versionCheck.error,
      });
      // Clear incompatible state
      await clearNavigationState(mode, userId);
      return null;
    }

    // Clean state before returning
    const cleanedState = cleanNavigationState(state);
    if (!cleanedState) {
      logger.warn(LOG_SOURCE, 'Failed to clean loaded navigation state, clearing it');
      await clearNavigationState(mode, userId);
      return null;
    }

    logger.debug(LOG_SOURCE, 'Navigation state loaded and validated from storage', {
      key: storageKey,
      stateSize: stateString.length,
    });

    return cleanedState;
  } catch (error) {
    logger.error(LOG_SOURCE, 'Error loading navigation state', { error });
    return null;
  }
};

/**
 * Clear navigation state for a specific mode and user
 * Useful when user logs out or mode changes
 */
export const clearNavigationState = async (
  mode: string,
  userId: string | null
): Promise<void> => {
  try {
    const storageKey = getStorageKey(mode, userId, Platform.OS);

    if (Platform.OS === 'web') {
      // Web: synchronous localStorage
      if (typeof window !== 'undefined' && window.localStorage) {
        window.localStorage.removeItem(storageKey);
        logger.debug(LOG_SOURCE, 'Navigation state cleared from localStorage', { key: storageKey });
      }
    } else {
      // Native: asynchronous AsyncStorage
      await AsyncStorage.removeItem(storageKey);
      logger.debug(LOG_SOURCE, 'Navigation state cleared from AsyncStorage', { key: storageKey });
    }
  } catch (error) {
    logger.error(LOG_SOURCE, 'Error clearing navigation state', { error });
  }
};

/**
 * Clear all navigation states (useful for cleanup)
 */
export const clearAllNavigationStates = async (): Promise<void> => {
  try {
    if (Platform.OS === 'web') {
      // Web: remove all keys matching the pattern
      if (typeof window !== 'undefined' && window.localStorage) {
        const keys = Object.keys(window.localStorage);
        keys.forEach((key) => {
          if (key.startsWith('nav_state_')) {
            window.localStorage.removeItem(key);
          }
        });
        logger.debug(LOG_SOURCE, 'All navigation states cleared from localStorage');
      }
    } else {
      // Native: get all keys and remove matching ones
      const allKeys = await AsyncStorage.getAllKeys();
      const navKeys = allKeys.filter((key) => key.startsWith('nav_state_'));
      if (navKeys.length > 0) {
        await AsyncStorage.multiRemove(navKeys);
        logger.debug(LOG_SOURCE, 'All navigation states cleared from AsyncStorage', {
          count: navKeys.length,
        });
      }
    }
  } catch (error) {
    logger.error(LOG_SOURCE, 'Error clearing all navigation states', { error });
  }
};

// utils/navigationQueue.ts
// Navigation queue manager - ensures navigation actions are executed sequentially
// Prevents race conditions and navigation conflicts

import { NavigationContainerRef, StackActions } from '@react-navigation/native';
import {
  QueuedNavigationAction,
  NavigationQueueItem,
  NavigateAction,
  ResetAction,
  ReplaceAction,
  GoBackAction,
  SetParamsAction
} from '../types/navigation';
import { logger } from './loggerService';

const LOG_SOURCE = 'NavigationQueue';

class NavigationQueue {
  private queue: NavigationQueueItem[] = [];
  private isProcessing = false;
  private navigationRef: NavigationContainerRef<any> | null = null;
  private defaultPriority = 0;

  /**
   * Initialize the navigation queue with a navigation ref
   */
  initialize(ref: NavigationContainerRef<any> | null): void {
    this.navigationRef = ref;
    logger.debug(LOG_SOURCE, 'Navigation queue initialized', { hasRef: !!ref });
  }

  /**
   * Check if navigation is ready
   */
  private isReady(): boolean {
    return this.navigationRef !== null && this.navigationRef.isReady();
  }

  /**
   * Add navigation action to queue
   */
  private enqueue(
    action: QueuedNavigationAction,
    priority: number = this.defaultPriority
  ): Promise<void> {
    return new Promise<void>((resolve, reject) => {
      const item: NavigationQueueItem = {
        id: `${Date.now()}-${Math.random()}`,
        action,
        priority,
        timestamp: Date.now(),
        resolve,
        reject,
      };

      // Insert based on priority (higher priority first)
      const insertIndex = this.queue.findIndex(q => q.priority < priority);
      if (insertIndex === -1) {
        this.queue.push(item);
      } else {
        this.queue.splice(insertIndex, 0, item);
      }

      logger.debug(LOG_SOURCE, 'Navigation action enqueued', {
        id: item.id,
        type: action.type,
        priority,
        queueLength: this.queue.length,
      });

      // Start processing if not already processing
      if (!this.isProcessing) {
        this.processQueue();
      }
    });
  }

  /**
   * Process the navigation queue
   */
  private async processQueue(): Promise<void> {
    if (this.isProcessing) {
      return;
    }

    this.isProcessing = true;

    while (this.queue.length > 0) {
      const item = this.queue.shift();
      if (!item) {
        break;
      }

      // Wait a bit to ensure previous navigation completed
      await new Promise(resolve => setTimeout(resolve, 10));

      // Check if navigation is ready
      if (!this.isReady()) {
        logger.warn(LOG_SOURCE, 'Navigation not ready, skipping action', {
          id: item.id,
          type: item.action.type,
        });
        item.reject(new Error('Navigation not ready'));
        continue;
      }

      try {
        await this.executeAction(item.action);
        item.resolve();
        logger.debug(LOG_SOURCE, 'Navigation action executed successfully', {
          id: item.id,
          type: item.action.type,
        });
      } catch (error) {
        logger.error(LOG_SOURCE, 'Navigation action failed', {
          id: item.id,
          type: item.action.type,
          error,
        });
        item.reject(error);
      }
    }

    this.isProcessing = false;
  }

  /**
   * Execute a navigation action
   */
  private async executeAction(action: QueuedNavigationAction): Promise<void> {
    if (!this.navigationRef) {
      throw new Error('Navigation ref not initialized');
    }

    switch (action.type) {
      case 'navigate':
        await this.executeNavigate(action);
        break;
      case 'reset':
        await this.executeReset(action);
        break;
      case 'replace':
        await this.executeReplace(action);
        break;
      case 'goBack':
        await this.executeGoBack(action);
        break;
      case 'setParams':
        await this.executeSetParams(action);
        break;
      default:
        throw new Error(`Unknown navigation action type: ${(action as any).type}`);
    }
  }

  /**
   * Execute navigate action
   */
  private async executeNavigate(action: NavigateAction): Promise<void> {
    if (!this.navigationRef) {
      throw new Error('Navigation ref not initialized');
    }

    (this.navigationRef.navigate as any)(action.routeName, action.params);
  }

  /**
   * Execute reset action
   */
  private async executeReset(action: ResetAction): Promise<void> {
    if (!this.navigationRef) {
      throw new Error('Navigation ref not initialized');
    }

    this.navigationRef.reset({
      index: action.index,
      routes: action.routes as any,
    });
  }

  /**
   * Execute replace action
   */
  private async executeReplace(action: ReplaceAction): Promise<void> {
    if (!this.navigationRef) {
      throw new Error('Navigation ref not initialized');
    }

    // Use StackActions.replace with dispatch since NavigationContainerRef doesn't have replace directly
    this.navigationRef.dispatch(
      StackActions.replace(action.routeName, action.params)
    );
  }

  /**
   * Execute goBack action
   */
  private async executeGoBack(_action: GoBackAction): Promise<void> {
    if (!this.navigationRef) {
      throw new Error('Navigation ref not initialized');
    }

    this.navigationRef.goBack();
  }

  /**
   * Execute setParams action
   */
  private async executeSetParams(action: SetParamsAction): Promise<void> {
    if (!this.navigationRef) {
      throw new Error('Navigation ref not initialized');
    }

    // setParams requires getting the current route first
    const state = this.navigationRef.getRootState();
    if (!state) {
      throw new Error('Cannot get navigation state for setParams');
    }

    // Find the current route
    const findCurrentRoute = (navState: any): any => {
      if (!navState.routes || navState.routes.length === 0) {
        return null;
      }
      const currentRoute = navState.routes[navState.index || 0];
      if (currentRoute.state) {
        return findCurrentRoute(currentRoute.state);
      }
      return currentRoute;
    };

    const currentRoute = findCurrentRoute(state);
    if (!currentRoute) {
      throw new Error('Cannot find current route for setParams');
    }

    // Use the route's key to set params
    if (currentRoute.key) {
      this.navigationRef.setParams({
        ...currentRoute.params,
        ...action.params,
      } as any);
    } else {
      // Fallback: try to set params on the current route
      this.navigationRef.setParams(action.params as any);
    }
  }

  /**
   * Public API: Navigate to a route
   */
  navigate(routeName: string, params?: Record<string, any>, priority: number = 0): Promise<void> {
    return this.enqueue(
      {
        type: 'navigate',
        routeName,
        params,
      },
      priority
    );
  }

  /**
   * Public API: Reset navigation stack
   */
  reset(index: number, routes: Array<{ name: string; params?: Record<string, any> }>, priority: number = 1): Promise<void> {
    return this.enqueue(
      {
        type: 'reset',
        index,
        routes,
      },
      priority
    );
  }

  /**
   * Public API: Replace current route
   */
  replace(routeName: string, params?: Record<string, any>, priority: number = 1): Promise<void> {
    return this.enqueue(
      {
        type: 'replace',
        routeName,
        params,
      },
      priority
    );
  }

  /**
   * Public API: Go back
   */
  goBack(priority: number = 0): Promise<void> {
    return this.enqueue(
      {
        type: 'goBack',
      },
      priority
    );
  }

  /**
   * Public API: Set params on current route
   */
  setParams(params: Record<string, any>, priority: number = 0): Promise<void> {
    return this.enqueue(
      {
        type: 'setParams',
        params,
      },
      priority
    );
  }

  /**
   * Clear the queue (useful for cleanup or error recovery)
   */
  clear(): void {
    const items = [...this.queue];
    this.queue = [];
    items.forEach(item => {
      item.reject(new Error('Navigation queue cleared'));
    });
    logger.warn(LOG_SOURCE, 'Navigation queue cleared', { clearedItems: items.length });
  }

  /**
   * Get queue status (for debugging)
   */
  getStatus(): { queueLength: number; isProcessing: boolean; hasRef: boolean } {
    return {
      queueLength: this.queue.length,
      isProcessing: this.isProcessing,
      hasRef: this.navigationRef !== null,
    };
  }
}

// Singleton instance
export const navigationQueue = new NavigationQueue();

// utils/navigationStateValidator.ts
// Navigation state validation and versioning
// Ensures navigation state is valid before saving/loading

import { NavigationState } from '@react-navigation/native';
import {
  NavigationStateValidationResult,
  NavigationStateVersion,
  VALID_ROUTES_MAP,
} from '../types/navigation';
import { logger } from './loggerService';

const LOG_SOURCE = 'NavigationStateValidator';

// Maximum size for navigation state (in bytes)
const MAX_STATE_SIZE = 100 * 1024; // 100KB

/**
 * Validates navigation state structure
 */
export const validateNavigationState = (
  state: NavigationState | null | undefined
): NavigationStateValidationResult => {
  const errors: string[] = [];
  const warnings: string[] = [];

  if (!state) {
    return { valid: false, errors: ['Navigation state is null or undefined'], warnings: [] };
  }

  // Check basic structure
  if (!state.routes || !Array.isArray(state.routes)) {
    errors.push('Navigation state must have a routes array');
    return { valid: false, errors, warnings };
  }

  if (state.routes.length === 0) {
    errors.push('Navigation state must have at least one route');
    return { valid: false, errors, warnings };
  }

  if (typeof state.index !== 'number' || state.index < 0 || state.index >= state.routes.length) {
    errors.push(`Navigation state index (${state.index}) is out of bounds for routes array (length: ${state.routes.length})`);
    return { valid: false, errors, warnings };
  }

  // Check state size
  try {
    const stateString = JSON.stringify(state);
    const stateSize = new Blob([stateString]).size;
    if (stateSize > MAX_STATE_SIZE) {
      warnings.push(`Navigation state size (${stateSize} bytes) exceeds recommended limit (${MAX_STATE_SIZE} bytes)`);
    }
  } catch {
    warnings.push('Could not calculate navigation state size');
  }

  // Validate routes recursively
  const validateRoute = (route: any, stackName: string = 'RootStack', depth: number = 0): void => {
    if (depth > 10) {
      errors.push('Navigation state has too many nested levels (max 10)');
      return;
    }

    if (!route || typeof route !== 'object') {
      errors.push(`Route at depth ${depth} is not a valid object`);
      return;
    }

    if (!route.name || typeof route.name !== 'string') {
      errors.push(`Route at depth ${depth} is missing a valid name`);
      return;
    }

    // Check if route name is valid for the current stack
    const validRoutes = VALID_ROUTES_MAP[stackName] || [];
    if (validRoutes.length > 0 && !validRoutes.includes(route.name)) {
      warnings.push(`Route "${route.name}" is not in the standard route list for ${stackName}`);
    }

    // Validate nested state
    if (route.state) {
      if (!route.state.routes || !Array.isArray(route.state.routes)) {
        errors.push(`Route "${route.name}" has invalid nested state`);
        return;
      }

      if (route.state.index !== undefined) {
        if (typeof route.state.index !== 'number' ||
          route.state.index < 0 ||
          route.state.index >= route.state.routes.length) {
          errors.push(`Route "${route.name}" has invalid nested state index`);
          return;
        }
      }

      // Determine nested stack name based on route name
      let nestedStackName = stackName;
      if (route.name === 'HomeStack' || route.name === 'HomeScreen') {
        nestedStackName = 'HomeTabStack';
      } else if (route.name === 'SearchTab') {
        nestedStackName = 'SearchTabStack';
      } else if (route.name === 'ProfileScreen') {
        nestedStackName = 'ProfileTabStack';
      } else if (route.name === 'DonationsTab') {
        nestedStackName = 'DonationsStack';
      } else if (route.name === 'AdminTab') {
        nestedStackName = 'AdminStack';
      } else if (route.name === 'BottomTab') {
        nestedStackName = 'BottomTab';
      }

      // Validate nested routes
      route.state.routes.forEach((nestedRoute: any, _nestedIndex: number) => {
        validateRoute(nestedRoute, nestedStackName, depth + 1);
      });
    }
  };

  // Validate all routes
  state.routes.forEach((route, _index) => {
    validateRoute(route, 'RootStack', 0);
  });

  const valid = errors.length === 0;

  if (!valid) {
    logger.warn(LOG_SOURCE, 'Navigation state validation failed', { errors, warnings });
  } else if (warnings.length > 0) {
    logger.debug(LOG_SOURCE, 'Navigation state validation passed with warnings', { warnings });
  }

  return { valid, errors, warnings };
};

/**
 * Checks if navigation state version is compatible
 */
export const checkNavigationStateVersion = (
  state: NavigationState | null | undefined
): { compatible: boolean; version?: NavigationStateVersion; error?: string } => {
  if (!state) {
    return { compatible: false, error: 'State is null or undefined' };
  }

  // Check for version in state (stored in route params or state key)
  // For now, we'll be lenient and accept states without version (backward compatibility)
  // In the future, we can add version checking here

  return { compatible: true };
};

/**
 * Validates and cleans navigation state
 * Removes invalid routes and fixes common issues
 */
export const cleanNavigationState = (
  state: NavigationState | null | undefined
): NavigationState | null => {
  if (!state) {
    return null;
  }

  const validation = validateNavigationState(state);
  if (!validation.valid) {
    logger.warn(LOG_SOURCE, 'Cannot clean invalid navigation state', { errors: validation.errors });
    return null;
  }

  // For now, return state as-is if valid
  // In the future, we can add cleaning logic here (e.g., remove invalid routes, fix indices)
  return state;
};

/**
 * Checks if a route name is valid
 */
export const isValidRouteName = (routeName: string, stackName: string = 'RootStack'): boolean => {
  const validRoutes = VALID_ROUTES_MAP[stackName] || [];
  return validRoutes.includes(routeName);
};

/**
 * Gets all valid route names for a stack
 */
export const getValidRouteNames = (stackName: string): string[] => {
  return VALID_ROUTES_MAP[stackName] || [];
};

// File overview:
// - Purpose: Service for handling post likes and comments operations
// - Provides: toggleLike, getComments, addComment, deleteComment, toggleCommentLike
// - Communicates with: /api/posts/* endpoints on the backend

import { API_BASE_URL } from './config.constants';
import AsyncStorage from '@react-native-async-storage/async-storage';

export interface PostsApiResponse<T = any> {
  success: boolean;
  data?: T;
  error?: string;
  total?: number;
}

export interface LikeResponse {
  post_id: string;
  is_liked: boolean;
  likes_count: number;
}

export interface CommentUser {
  id: string;
  name: string;
  avatar_url: string;
}

export interface Comment {
  id: string;
  post_id: string;
  user_id: string;
  text: string;
  likes_count: number;
  is_liked: boolean;
  created_at: string;
  updated_at: string;
  user: CommentUser;
}

export interface CommentResponse extends Comment {
  comments_count: number;
}

export interface CommentLikeResponse {
  comment_id: string;
  is_liked: boolean;
  likes_count: number;
}

class PostsService {
  private baseURL: string;

  constructor() {
    this.baseURL = API_BASE_URL;
  }

  private async getAuthToken(): Promise<string | null> {
    try {
      // Try to get JWT access token from AsyncStorage
      const jwtToken = await AsyncStorage.getItem('jwt_access_token');

      if (jwtToken) {
        // Check if token is expired
        const expiresAt = await AsyncStorage.getItem('jwt_token_expires_at');
        if (expiresAt && parseInt(expiresAt) > Date.now()) {
          return jwtToken;
        }
      }

      // Fallback: Try to get Firebase ID token
      try {
        const { getFirebase } = await import('./firebaseClient');
        const { getAuth } = await import('firebase/auth');
        const { app } = getFirebase();
        const auth = getAuth(app);
        const user = auth.currentUser;

        if (user) {
          const token = await user.getIdToken();
          return token;
        }
      } catch (firebaseError) {
        console.warn('Firebase auth not available:', firebaseError);
      }
    } catch (error) {
      console.warn('Failed to get auth token:', error);
    }

    return null;
  }

  private async request<T>(
    endpoint: string,
    options: RequestInit = {}
  ): Promise<PostsApiResponse<T>> {
    try {
      const url = `${this.baseURL}${endpoint}`;

      // Get authentication token
      const authToken = await this.getAuthToken();

      const config: RequestInit = {
        headers: {
          'Content-Type': 'application/json',
          ...(authToken ? { 'Authorization': `Bearer ${authToken}` } : {}),
          ...options.headers,
        },
        ...options,
      };

      console.log(`🌐 PostsService Request: ${config.method || 'GET'} ${url}`, {
        hasAuth: !!authToken,
        authTokenLength: authToken?.length || 0
      });

      const response = await fetch(url, config);
      const data = await response.json();

      if (!response.ok) {
        console.error(`❌ PostsService Error: ${response.status}`, {
          status: response.status,
          statusText: response.statusText,
          data,
          endpoint,
          hasAuth: !!authToken
        });
        return {
          success: false,
          error: data.message || data.error || `HTTP ${response.status}: ${response.statusText}`,
        };
      }

      console.log(`✅ PostsService Response: ${endpoint}`, data);
      return data;
    } catch (error) {
      console.error(`❌ PostsService Network Error:`, error);
      return {
        success: false,
        error: 'Network error - please check your connection',
      };
    }
  }

  // ============================================
  // POSTS
  // ============================================

  /**
   * Get main feed posts
   * @param limit - Max number of results
   * @param offset - Pagination offset
   * @param userId - Optional: filter by user ID (for profile feed) or for "friends" logic checking (backend dependant)
   * @param postType - Optional: filter by post type (e.g., 'item', 'ride', 'donation')
   * @param itemId - Optional: filter by item_id
   * @param rideId - Optional: filter by ride_id
   */
  async getPosts(
    limit = 20,
    offset = 0,
    userId?: string,
    postType?: string,
    itemId?: string,
    rideId?: string
  ): Promise<PostsApiResponse<any[]>> {
    let url = `/api/posts?limit=${limit}&offset=${offset}`;
    if (userId) {
      url += `&user_id=${userId}`;
    }
    if (postType) {
      url += `&post_type=${encodeURIComponent(postType)}`;
    }
    if (itemId) {
      url += `&item_id=${encodeURIComponent(itemId)}`;
    }
    if (rideId) {
      url += `&ride_id=${encodeURIComponent(rideId)}`;
    }
    return this.request<any[]>(url);
  }

  /**
   * Get specific user's posts
   * @param targetUserId - The ID of the user whose posts to fetch
   * @param viewerId - The ID of the current viewer (to check likes)
   * @param limit
   * @param offset
   */
  async getUserPosts(targetUserId: string, viewerId?: string, limit = 20, _offset = 0): Promise<PostsApiResponse<any[]>> {
    let url = `/api/posts/user/${targetUserId}?limit=${limit}`;
    if (viewerId) {
      url += `&viewer_id=${viewerId}`;
    }
    // Note: Pagination offset support might need to be added to backend getUserPosts if missing, 
    // likely it supports it or we rely on limit for now.
    return this.request<any[]>(url);
  }

  // ============================================
  // LIKES
  // ============================================

  /**
   * Toggle like on a post (like if not liked, unlike if liked)
   * @param postId - The ID of the post
   * @param userId - The ID of the user
   * @returns {Promise<PostsApiResponse<LikeResponse>>}
   */
  async togglePostLike(postId: string, userId: string): Promise<PostsApiResponse<LikeResponse>> {
    return this.request<LikeResponse>(`/api/posts/${postId}/like`, {
      method: 'POST',
      body: JSON.stringify({ user_id: userId }),
    });
  }

  /**
   * Check if a user has liked a post
   * @param postId - The ID of the post
   * @param userId - The ID of the user
   */
  async checkUserLikedPost(postId: string, userId: string): Promise<PostsApiResponse<{ is_liked: boolean }>> {
    return this.request<{ is_liked: boolean }>(`/api/posts/${postId}/likes/check/${userId}`);
  }

  /**
   * Get list of users who liked a post
   * @param postId - The ID of the post
   * @param limit - Max number of results (default 50)
   * @param offset - Pagination offset (default 0)
   */
  async getPostLikes(postId: string, limit = 50, offset = 0): Promise<PostsApiResponse<any[]>> {
    return this.request<any[]>(`/api/posts/${postId}/likes?limit=${limit}&offset=${offset}`);
  }

  // ============================================
  // COMMENTS
  // ============================================

  /**
   * Get all comments for a post
   * @param postId - The ID of the post
   * @param viewerId - Optional viewer ID to check if they liked each comment
   * @param limit - Max number of results (default 50)
   * @param offset - Pagination offset (default 0)
   */
  async getPostComments(
    postId: string,
    viewerId?: string,
    limit = 50,
    offset = 0
  ): Promise<PostsApiResponse<Comment[]>> {
    let url = `/api/posts/${postId}/comments?limit=${limit}&offset=${offset}`;
    if (viewerId) {
      url += `&viewer_id=${viewerId}`;
    }
    return this.request<Comment[]>(url);
  }

  /**
   * Add a comment to a post
   * @param postId - The ID of the post
   * @param userId - The ID of the user
   * @param text - The comment text (max 2000 characters)
   */
  async addComment(postId: string, userId: string, text: string): Promise<PostsApiResponse<CommentResponse>> {
    return this.request<CommentResponse>(`/api/posts/${postId}/comments`, {
      method: 'POST',
      body: JSON.stringify({ user_id: userId, text }),
    });
  }

  /**
   * Update a comment (only owner can update)
   * @param postId - The ID of the post
   * @param commentId - The ID of the comment
   * @param userId - The ID of the user (must be comment owner)
   * @param text - The new comment text
   */
  async updateComment(
    postId: string,
    commentId: string,
    userId: string,
    text: string
  ): Promise<PostsApiResponse<Comment>> {
    return this.request<Comment>(`/api/posts/${postId}/comments/${commentId}`, {
      method: 'PUT',
      body: JSON.stringify({ user_id: userId, text }),
    });
  }

  /**
   * Delete a comment (only owner can delete)
   * @param postId - The ID of the post
   * @param commentId - The ID of the comment
   * @param userId - The ID of the user (must be comment owner)
   */
  async deleteComment(
    postId: string,
    commentId: string,
    userId: string
  ): Promise<PostsApiResponse<{ deleted_comment_id: string; comments_count: number }>> {
    return this.request<{ deleted_comment_id: string; comments_count: number }>(
      `/api/posts/${postId}/comments/${commentId}?user_id=${userId}`,
      { method: 'DELETE' }
    );
  }

  /**
   * Toggle like on a comment
   * @param postId - The ID of the post
   * @param commentId - The ID of the comment
   * @param userId - The ID of the user
   */
  async toggleCommentLike(
    postId: string,
    commentId: string,
    userId: string
  ): Promise<PostsApiResponse<CommentLikeResponse>> {
    return this.request<CommentLikeResponse>(
      `/api/posts/${postId}/comments/${commentId}/like`,
      {
        method: 'POST',
        body: JSON.stringify({ user_id: userId }),
      }
    );
  }

  // ============================================
  // POST MANAGEMENT
  // ============================================

  /**
   * Update a post (title, description, image)
   * @param postId - The ID of the post
   * @param userId - The ID of the user (must be post owner)
   * @param updates - Object containing fields to update
   */
  async updatePost(
    postId: string,
    userId: string,
    updates: { title?: string; description?: string; image?: string }
  ): Promise<PostsApiResponse<any>> {
    return this.request<any>(`/api/posts/${postId}`, {
      method: 'PUT',
      body: JSON.stringify({ user_id: userId, ...updates }),
    });
  }

  /**
   * Hide a post (soft delete - sets status to 'hidden')
   * @param postId - The ID of the post
   * @param userId - The ID of the user (must be post owner)
   */
  async hidePost(postId: string, userId: string): Promise<PostsApiResponse<{ status: string }>> {
    return this.request<{ status: string }>(`/api/posts/${postId}/hide`, {
      method: 'POST',
      body: JSON.stringify({ user_id: userId }),
    });
  }

  /**
   * Unhide a post (restore from hidden status)
   * @param postId - The ID of the post
   * @param userId - The ID of the user (must be post owner)
   */
  async unhidePost(postId: string, userId: string): Promise<PostsApiResponse<{ status: string }>> {
    return this.request<{ status: string }>(`/api/posts/${postId}/unhide`, {
      method: 'POST',
      body: JSON.stringify({ user_id: userId }),
    });
  }
}

// Export singleton instance
export const postsService = new PostsService();

// Export default for backward compatibility
export default postsService;
